        /* 五大区域背景 */
        .map-region {
            position: absolute;
            border: 2px solid rgba(136, 149, 177, 0.4);
            background: rgba(0, 0, 0, 0.1);
            transition: all 0.3s ease;
            border-radius: 8px;
            box-shadow: inset 0 0 20px rgba(0, 0, 0, 0.1);
            z-index: 1;
        }

        .map-region:hover {
            background: rgba(78, 205, 196, 0.05);
            border-color: rgba(78, 205, 196, 0.6);
            box-shadow: inset 0 0 30px rgba(78, 205, 196, 0.1);
        }

        .map-region-label {
            position: absolute;
            top: 10px;
            left: 10px;
            font-size: 13px;
            font-weight: 700;
            color: #4ECDC4;
            text-shadow: 0 0 5px rgba(0, 0, 0, 0.8);
            pointer-events: none;
            background: rgba(0, 0, 0, 0.4);
            padding: 5px 12px;
            border-radius: 5px;
            backdrop-filter: blur(5px);
            z-index: 2;
        }

        /* 迷雾效果已删除 */

        .map-marker {
            position: absolute;
            width: 10px; /* 从16px缩小到10px */
            height: 10px; /* 从16px缩小到10px */
            border-radius: 50%;
            border: 2px solid #4ECDC4; /* 从3px缩小到2px */
            background: radial-gradient(circle at 30% 30%, rgba(78, 205, 196, 0.8), rgba(78, 205, 196, 0.3));
            cursor: pointer;
            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
            box-shadow: 
                0 0 10px rgba(78, 205, 196, 0.6), /* 缩小阴影范围 */
                0 2px 6px rgba(0, 0, 0, 0.3),
                inset 0 1px 2px rgba(255, 255, 255, 0.3);
            z-index: 100;
        }

        .map-marker::before {
            content: '';
            position: absolute;
            width: 100%;
            height: 100%;
            border-radius: 50%;
            background: inherit;
            animation: ripple 2s cubic-bezier(0, 0, 0.2, 1) infinite;
            z-index: -1;
        }

        @keyframes ripple {
            0% {
                transform: scale(1);
                opacity: 1;
            }
            100% {
                transform: scale(2.5);
                opacity: 0;
            }
        }

        .map-marker:hover {
            transform: scale(1.8); /* 从2倍缩小到1.8倍，使hover时不会太大 */
            background: radial-gradient(circle at 30% 30%, rgba(78, 205, 196, 1), rgba(78, 205, 196, 0.5));
            box-shadow: 
                0 0 18px rgba(78, 205, 196, 1), /* 调整阴影范围 */
                0 4px 12px rgba(0, 0, 0, 0.4),
                inset 0 1px 3px rgba(255, 255, 255, 0.5);
            z-index: 200;
        }

        .map-marker.current {
            width: 14px; /* 从22px缩小到14px */
            height: 14px; /* 从22px缩小到14px */
            background: radial-gradient(circle at 30% 30%, rgba(253, 183, 0, 1), rgba(253, 183, 0, 0.4));
            border-color: #FDB700;
            border-width: 2.5px; /* 从4px缩小到2.5px */
            box-shadow: 
                0 0 18px rgba(253, 183, 0, 1), /* 缩小阴影范围 */
                0 0 32px rgba(253, 183, 0, 0.6), /* 缩小阴影范围 */
                0 4px 12px rgba(0, 0, 0, 0.5),
                inset 0 1px 3px rgba(255, 255, 255, 0.5);
            animation: pulse 2s ease-in-out infinite;
            z-index: 300;
        }

        .map-marker.coord-only {
            width: 8px; /* 稍微小一些 */
            height: 8px;
            background: radial-gradient(circle at 30% 30%, rgba(173, 216, 230, 0.8), rgba(173, 216, 230, 0.3)); /* 浅蓝色 */
            border-color: #ADD8E6; /* 浅蓝色边框 */
            box-shadow: 
                0 0 8px rgba(173, 216, 230, 0.6),
                0 2px 6px rgba(0, 0, 0, 0.3),
                inset 0 1px 2px rgba(255, 255, 255, 0.3);
        }

        .map-marker.coord-only .map-marker-label {
            color: #ADD8E6; /* 浅蓝色文字，与标记点颜色一致 */
            font-size: 9px; /* 更小的字体，适合坐标显示 */
        }

        .map-marker.current::before {
            animation: ripple 1.5s cubic-bezier(0, 0, 0.2, 1) infinite;
        }

        .map-marker.unexplored {
            border-color: #8895B1;
            background: radial-gradient(circle at 30% 30%, rgba(136, 149, 177, 0.4), rgba(136, 149, 177, 0.1));
            box-shadow: 
                0 0 8px rgba(136, 149, 177, 0.3),
                0 2px 6px rgba(0, 0, 0, 0.2);
        }

        .map-marker.unexplored::before {
            opacity: 0.3;
        }

        @keyframes pulse {
            0%, 100% {
                transform: scale(1);
                opacity: 1;
            }
            50% {
                transform: scale(1.25); /* 从1.3调整到1.25，使动画更协调 */
                opacity: 0.8;
            }
        }

        .map-marker-label {
            position: absolute;
            bottom: -25px; /* 从-30px调整到-25px，让标签离标记更近 */
            left: 50%;
            transform: translateX(-50%);
            background: rgba(0, 0, 0, 0.9);
            color: #4ECDC4;
            padding: 4px 8px; /* 从6px 12px缩小到4px 8px */
            font-size: 10px; /* 从11px缩小到10px */
            white-space: nowrap;
            opacity: 1;
            transition: all 0.3s ease;
            pointer-events: none;
            border: 1px solid rgba(78, 205, 196, 0.4);
            border-radius: 3px; /* 从4px缩小到3px */
            box-shadow: 0 2px 8px rgba(0, 0, 0, 0.6);
            z-index: 101;
            max-width: 180px; /* 从200px缩小到180px */
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .map-marker:hover .map-marker-label {
            background: rgba(78, 205, 196, 0.3);
            color: #EFF1FE;
            bottom: -30px; /* 从-35px调整到-30px */
            font-size: 11px; /* 从12px缩小到11px */
            padding: 5px 10px; /* 从7px 14px缩小到5px 10px */
            box-shadow: 0 3px 10px rgba(0, 0, 0, 0.7);
            z-index: 201;
            max-width: 220px; /* 从250px缩小到220px */
        }

        .map-marker.current .map-marker-label {
            color: #FDB700;
            border-color: #FDB700;
            background: rgba(253, 183, 0, 0.2);
            font-weight: 700;
            font-size: 10px; /* 明确设置字体大小 */
