            return `<div class="skill-progress-bar">
                <div class="skill-progress-fill ${isNegative ? 'negative' : ''}" style="width: ${Math.abs(percent)}%"></div>
            </div>`;
        }

        function getColorName(color) {
            const hex = color.replace('#', '');
            const r = parseInt(hex.substr(0, 2), 16);
            const g = parseInt(hex.substr(2, 2), 16);
            const b = parseInt(hex.substr(4, 2), 16);
            if (r < 50 && g < 50 && b < 50) return '深色';
            if (r > 200 && g > 200 && b > 200) return '浅色';
            if (r > g && r > b) return '红色系';
            if (g > r && g > b) return '绿色系';
            if (b > r && b > g) return '蓝色系';
            if (r > 150 && g > 150 && b < 100) return '黄色系';
            if (r > 150 && g < 100 && b > 150) return '紫色系';
            if (r < 100 && g > 150 && b > 150) return '青色系';
            if (r > 150 && g > 100 && b < 100) return '橙色系';
            return '自定义颜色';
        }

        function hexToRgba(hex, opacity) {
            const r = parseInt(hex.slice(1, 3), 16);
            const g = parseInt(hex.slice(3, 5), 16);
            const b = parseInt(hex.slice(5, 7), 16);
            return `rgba(${r}, ${g}, ${b}, ${opacity})`;
        }

        function parseFields(rawData, configs) {
            console.log('开始解析字段');
            configs.forEach(function (cfg, index) {
                var pattern = cfg.pattern;
                var elementId = cfg.elementId;
                var callback = cfg.callback;
                var match = rawData.match(pattern);
                console.log('字段', index + 1, ':', cfg.pattern.toString(), '匹配结果:', match);
                if (!match) {
                    return;
                }
                if (typeof callback === 'function') {
                    callback(match);
                } else if (elementId) {
                    var el = document.getElementById(elementId);
                    if (el) {
                        el.textContent = match[1].trim();
                        console.log('更新元素', elementId, '内容:', match[1].trim());
                    }
                }
            });
        }

