            extractedText = extractedText.replace(/<StatusPlaceHolderImpl\/>/g, '');

            // 2. 移除status_menu标签及其内容
            extractedText = extractedText.replace(/<status_menu>[\s\S]*?<\/status_menu>/g, '');

            // 3. 移除UpdateVariable标签及其内容
            extractedText = extractedText.replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/g, '');

            // 同时处理原始fullText，确保在提取content之前就移除这些标签
            // 这样可以确保无论标签在哪里出现都能被移除
            fullText = fullText.replace(/<StatusPlaceHolderImpl\/>/g, '');
            fullText = fullText.replace(/<status_menu>[\s\S]*?<\/status_menu>/g, '');
            fullText = fullText.replace(/<UpdateVariable>[\s\S]*?<\/UpdateVariable>/g, '');

            // 清理多余的空白字符
            extractedText = extractedText.trim();

            // 创建或更新main-text-data元素，供parseMainText函数使用
            var mainTextScript = document.getElementById('main-text-data');
            if (!mainTextScript) {
                mainTextScript = document.createElement('script');
