        function applyOpacity(value) {
            var num = parseInt(value, 10);
            if (isNaN(num)) {
                num = 100;
            }
            $('#opacity-value').text(num);

            const opacity = num / 100;
            const color = localStorage.getItem('wanyu-colorTheme') || '#1a1a2e';
            const rgbaColor = hexToRgba(color, opacity * 0.8);

            document.querySelectorAll('.left-sidebar').forEach(el => {
                el.style.backgroundColor = rgbaColor;
            });

            document.querySelectorAll('.content-panel').forEach(el => {
                el.style.backgroundColor = rgbaColor;
            });

            document.querySelectorAll('.panel').forEach(el => {
                el.style.backgroundColor = rgbaColor;
            });

            try {
                localStorage.setItem('wanyu-opacity', String(num));
            } catch (e) {}
        }

        function applyFontSize(value) {
            var num = parseInt(value, 10);
            if (isNaN(num)) {
                num = 14;
            }
            $('#font-size-value').text(num);
            $('body').css('font-size', num + 'px');
            try {
                localStorage.setItem('wanyu-fontSize', String(num));
            } catch (e) {}
        }

        function applyBrightness(value) {
            var num = parseInt(value, 10);
            if (isNaN(num)) {
                num = 100;
            }
            $('#brightness-value').text(num);
            var opacity = num / 100 * 0.7;
            document.body.style.backgroundColor = 'rgba(10, 20, 30, ' + opacity + ')';
            try {
                localStorage.setItem('wanyu-brightness', String(num));
            } catch (e) {}
        }

