                if (!data || !data.万域) {
                    return;
                }

                const wanyu = data.万域;

                // 渲染时间
                const time = wanyu.时间 || {};
                if (time.纪元名称 != null && time.年 != null && time.月 != null && time.日 != null) {
                    $('#time-date').text(`${time.纪元名称}${time.年}年-${time.月}月-${time.日}日`);
                }
                if (time.时辰 != null) {
                    $('#time-hour').text(time.时辰);
                }

                // 渲染天气
                if (wanyu.天气 != null) {
                    $('#weather-value').text(wanyu.天气);
                }

                // 渲染位置
                const location = wanyu.位置 || {};
                if (location.界 != null) {
                    $('#location-world').text(location.界);
                }
                const parts = [location.大陆, location.区域, location.具体地点].filter(Boolean);
                if (parts.length) {
                    $('#location-place').text(parts.join('·'));
                }

                // 渲染灵气
                const aura = wanyu.灵气 || {};
                if (aura.浓度 != null) {
                    $('#aura-density').text(aura.浓度);
                }
                if (aura.描述 != null) {
                    $('#aura-description').text(aura.描述);
                }

                // 注意：这里不再渲染正文，正文完全由 extractMainTextModule/parseMainText 负责
            } catch (error) {
                console.error('渲染万域系统失败:', error);
            }
        }

