        }

        // 储物囊
        const storage = char.持有物品?.储物囊 || {};
        const storageKeys = Object.keys(storage);
        if (storageKeys.length > 0) {
            let storageHtml = '';
            storageKeys.forEach(key => {
                const item = storage[key];
                storageHtml += `
                    <div class="collapsible-item">
