                        ${item.来源 ? `<div class="info-item"><span class="info-label">来源</span><span class="info-value">${item.来源}</span></div>` : ''}
                        ${item.功能 ? `<div class="info-item"><span class="info-label">功能</span><span class="info-value">${item.功能}</span></div>` : ''}
                        ${item.使用方法 ? `<div class="info-item"><span class="info-label">使用方法</span><span class="info-value">${item.使用方法}</span></div>` : ''}
                        ${item.外观描述 ? `<div class="info-item"><span class="info-label">外观描述</span><span class="info-value">${item.外观描述}</span></div>` : ''}
                        ${item.市场价值 ? `<div class="info-item"><span class="info-label">市场价值</span><span class="info-value">${item.市场价值}</span></div>` : ''}
                        ${item.稀有度 ? `<div class="info-item"><span class="info-label">稀有度</span><span class="info-value">${item.稀有度}</span></div>` : ''}
                        ${item.描述 ? `<div class="item-description">${item.描述}</div>` : ''}
                        <div class="field-card-footer">
                            <button class="action-btn transfer-btn" onclick="moveItemBetween('储物囊', '仓库', '${escapeJsString(key)}')">存入洞府仓库 →</button>
                        </div>
                        </div>
                    </div>
                `;
            });
            $('#storage-section').html(storageHtml);
        } else {
            $('#storage-section').html('<div class="empty-state">储物囊为空</div>');
        }

    } catch (error) {
        console.error('渲染主角信息失败:', error);
    }
}

