/* ==================== 宗门信息渲染 ==================== */
function renderSectInfo(data) {
    try {
        const sect = data.宗门信息 || {};

        // 基本信息
        $('#sect-name').text(sect.宗门名称 || '无门无派');
        $('#sect-leader').text(sect.掌门 || '');

        // 主角身份
        $('#protagonist-position').text(sect.宗门职位 || '无');
        $('#protagonist-contribution').text(sect.贡献度 || 0);
        $('#protagonist-promotion').text(sect.晋升条件 || '');

        // 隐藏空值元素
        if (!sect.掌门) {
            $('#leader-container').hide();
        } else {
            $('#leader-container').show();
        }

        if (!sect.晋升条件) {
            $('#promotion-container').hide();
        } else {
            $('#promotion-container').show();
        }

        // 宗门任务
        const tasks = sect.宗门任务 || {};
        const taskKeys = Object.keys(tasks);
        if (taskKeys.length > 0) {
            let tasksHtml = '';
            taskKeys.forEach(key => {
                const task = tasks[key];
                // 如果task是字符串，说明是简要描述
                if (typeof task === 'string') {
                    tasksHtml += `
                        <div class="task-item">
                            <div class="task-title">${key}</div>
                            <div class="task-description">${task}</div>
                        </div>
                    `;
                } else {
                    // 如果是对象，显示详细信息
                    tasksHtml += `
                        <div class="task-item">
                            <div class="task-header">
                                <span class="task-id">${key}</span>
                                ${task.类型 ? `<span class="task-type">${task.类型}</span>` : ''}
                                ${task.状态 ? `<span class="task-status ${task.状态 === '可接取' ? 'available' : task.状态 === '进行中' ? 'ongoing' : 'completed'}">${task.状态}</span>` : ''}
                            </div>
                            <div class="task-title">${task.标题 || key}</div>
                            ${task.描述 ? `<div class="task-description">${task.描述}</div>` : ''}
