/* ==================== 洞府信息渲染 ==================== */
function renderCaveInfo(data) {
    try {
        const cave = data.洞府信息 || {};

        // 基础信息
        $('#cave-name').text(cave.洞府名称 || '未建立');
        $('#cave-level').text(cave.等级 || '凡级');
        $('#cave-array').text(cave.当前阵法 || '无');
