                const item = storage[key];
                storageHtml += `
                    <div class="collapsible-item">
                        <div class="collapsible-header" onclick="toggleCollapsible(this)">
                            <span class="collapsible-title">${key}</span>
                            <span class="collapsible-arrow">▼</span>
