                                    </div>
                                    <div class="item-meta-values">
                                        ${item.类型 ? `<span class="meta-value">${item.类型}</span>` : ''}
                                        ${item.品阶 ? `<span class="meta-value">${item.品阶}</span>` : ''}
                                        ${item.数量 ? `<span class="meta-value">${item.数量}</span>` : ''}
