                            ${item.外观描述 ? `<div class="info-item"><span class="info-label">外观描述</span><span class="info-value">${item.外观描述}</span></div>` : ''}
                            ${item.市场价值 ? `<div class="info-item"><span class="info-label">市场价值</span><span class="info-value">${item.市场价值}</span></div>` : ''}
                            ${item.稀有度 ? `<div class="info-item"><span class="info-label">稀有度</span><span class="info-value">${item.稀有度}</span></div>` : ''}
