/* ==================== 地图渲染 ==================== */
function renderMapPanel(data) {
    try {
        const mapData = data.地图 || {};

        // 当前所处
        $('#current-location-name').text(mapData.所处区域名称 || '');
        $('#current-location-status').text(mapData.所处探索状态 || '未探索');
        $('#current-location-desc').text(mapData.所处描述 || '');
        $('#current-location-coords').text(`X: ${mapData.当前坐标X || 0}, Y: ${mapData.当前坐标Y || 0}`);

        // 隐藏空值元素
        if (!mapData.所处区域名称) {
            $('#location-name-container').hide();
        } else {
            $('#location-name-container').show();
        }

        // 清空地图标记
        $('#map-canvas').empty();

        let placesHtml = '';

        // 跟踪是否已经添加了所处位置的标记
        let currentLocationAdded = false;

        // 地点标记 - 首先处理所有已知地点（蓝色标记）
        const places = mapData.已知地点 || {};
        const placeKeys = Object.keys(places);

        if (placeKeys.length > 0) {
            placeKeys.forEach(key => {
                const place = places[key];

                // 添加地图标记
                const x = place.坐标X || 0;
                const y = place.坐标Y || 0;
                // 检查此地点是否为当前所处位置：仅基于距离匹配
                // 计算距离，单位为公里，1坐标单位=2公里
                const distance = Math.sqrt(Math.pow(x - (mapData.当前坐标X || 0), 2) + Math.pow(y - (mapData.当前坐标Y || 0), 2)) * 2;
                // 当距离小于等于2公里时，视为当前位置
                const isCurrent = distance <= 2;

                // 坐标转换：将世界坐标转换为百分比坐标
                const xPercent = ((x + 10000) / 20000) * 100;
                const yPercent = ((y + 8000) / 16000) * 100;

                // 生成坐标键，用于避免已知地点重复 - 四舍五入到整数以避免浮点精度问题
                const coordKey = `${Math.round(x)},${Math.round(y)}`;

                // 如果这个地点同时也是当前所处位置，额外添加一个金色标记
                // 重要：这个要先添加，以确保当前位置标记始终被放置，即使已知地点因去重被跳过
                if (isCurrent) {
                    const currentMarkerHtml = `
                        <div class="map-marker current"
                             style="left: ${xPercent}%; top: ${yPercent}%;">
                            <div class="map-marker-label">${mapData.所处区域名称 || key}</div>
                        </div>
                    `;
                    $('#map-canvas').append(currentMarkerHtml);
                    currentLocationAdded = true;
                }

                // 添加已知地点的标记（蓝色）
                const isCoordOnly = !key || key.startsWith('坐标点') || key === '坐标' || key === 'Coordinate' || !isNaN(parseFloat(key));
                const baseMarkerClass = ''; 
                const additionalClass = isCoordOnly ? 'coord-only' : '';
                const combinedClass = `${baseMarkerClass} ${additionalClass}`.trim();
                const labelContent = isCoordOnly ? `(${x}, ${y})` : key;

                const markerHtml = `
                    <div class="map-marker ${combinedClass}"
                         style="left: ${xPercent}%; top: ${yPercent}%;">
                        <div class="map-marker-label">${labelContent}</div>
                    </div>
                `;
                $('#map-canvas').append(markerHtml);

                // ===== 行程展示信息（直接读取变量） =====
                let badgeHtml = '';
                // 直接读取变量池中已计算好的行程信息。如果为空，显示暂无数据。
                let travelDetail = place.行程信息 || '暂无数据'; 

                // 如果该地点是当前所处位置，显示当前位置标记（但不覆盖行程信息）
                if (isCurrent) {
                    badgeHtml = `<span class="travel-badge at-location">📍当前位置</span>`;
                }

                placesHtml += `
                    <div class="place-item">
                        <div class="place-header">
                            <span class="place-name">${key}</span>
                            ${badgeHtml}
                        </div>
                        ${place.描述 ? `<div class="place-description">${place.描述}</div>` : ''}
                        ${place.已知信息 ? `<div class="place-info"><span class="info-prefix">已知:</span>${place.已知信息}</div>` : ''}
                        <div class="collapsible-section">
                            <div class="collapsible-header" onclick="toggleCollapsible(this)">
                                <span class="collapsible-title">详细信息</span>
                                <span class="collapsible-arrow">▼</span>
                            </div>
                            <div class="collapsible-content">
                        ${place.区域 ? `<div class="info-item"><span class="info-label">区域</span><span class="info-value">${place.区域}</span></div>` : ''}
                        <div class="info-item"><span class="info-label">坐标</span><span class="info-value">X: ${place.坐标X || 0}, Y: ${place.坐标Y || 0}</span></div>
                        ${place.类型 ? `<div class="info-item"><span class="info-label">类型</span><span class="info-value">${place.类型}</span></div>` : ''}
                        ${(place.探索度 !== undefined && place.探索度 !== null) ? `<div class="info-item"><span class="info-label">探索度</span><span class="info-value">${place.探索度}%</span></div>` : ''}
                        ${place.所属势力 ? `<div class="info-item"><span class="info-label">所属势力</span><span class="info-value">${place.所属势力}</span></div>` : ''}
                        ${place.描述 ? `<div class="info-item"><span class="info-label">描述</span><span class="info-value">${place.描述}</span></div>` : ''}
                        ${place.环境 ? `<div class="info-item"><span class="info-label">环境</span><span class="info-value">${place.环境}</span></div>` : ''}
                        ${place.灵气浓度 ? `<div class="info-item"><span class="info-label">灵气浓度</span><span class="info-value">${place.灵气浓度}</span></div>` : ''}
                        ${place.可获得资源 ? `<div class="info-item"><span class="info-label">可获得资源</span><span class="info-value">${place.可获得资源}</span></div>` : ''}
                        ${place.已知信息 ? `<div class="info-item"><span class="info-label">已知信息</span><span class="info-value">${place.已知信息}</span></div>` : ''}
                        ${place.当前事件 ? `<div class="info-item"><span class="info-label">当前事件</span><span class="info-value">${place.当前事件}</span></div>` : ''}
                        ${place.传闻与传说 ? `<div class="info-item"><span class="info-label">传闻与传说</span><span class="info-value">${place.传闻与传说}</span></div>` : ''}
                        ${place.危险程度 ? `<div class="info-item"><span class="info-label">危险程度</span><span class="info-value">${place.危险程度}</span></div>` : ''}
                        ${place.通行限制 ? `<div class="info-item"><span class="info-label">通行限制</span><span class="info-value">${place.通行限制}</span></div>` : ''}
                        ${place.名称 ? `<div class="info-item"><span class="info-label">名称</span><span class="info-value">${place.名称}</span></div>` : ''}
                        <div class="info-item"><span class="info-label">行程信息</span><span class="info-value">${travelDetail}</span></div>
                            </div>
                        </div>
                    </div>
                `;
            });
        }

        // 递归搜索所有包含坐标的对象
        const processedCoords = new Set(); // 避免重复添加
        const foundCoords = [];

        // 搜索函数：递归查找所有包含坐标X和坐标Y的对象
        function searchCoordinates(obj, path = '', name = '') {
            if (obj === null || typeof obj !== 'object') {
                return;
            }

            // 如果当前对象包含坐标X和坐标Y，则记录下来
            if (typeof obj.坐标X !== 'undefined' && typeof obj.坐标Y !== 'undefined') {
                // 优先使用对象本身的名称属性，否则使用路径的最后一段作为名称
                let coordName = name || path.split('.').pop() || '坐标点';
                // 如果coordName包含了多个部分（如"地图.已知地点.琼华京"），只取最后一部分
                if (coordName.includes('.')) {
                    coordName = coordName.split('.').pop() || coordName;
                }
                foundCoords.push({
                    name: coordName,
                    x: parseFloat(obj.坐标X) || 0,
                    y: parseFloat(obj.坐标Y) || 0,
                    path: path
                });
            }

            // 继续搜索子对象
            for (const key in obj) {
                if (obj.hasOwnProperty(key) && typeof obj[key] === 'object' && obj[key] !== null) {
                    const newPath = path ? `${path}.${key}` : key;
                    const newName = name ? `${name}.${key}` : key;
                    searchCoordinates(obj[key], newPath, newName);
                }
            }
        }

        // 开始搜索整个数据结构
        searchCoordinates(data);

        // 添加找到的坐标点（排除已知地点中的坐标）
        foundCoords.forEach(coord => {
            const uniqueKey = `${coord.name}_${coord.x}_${coord.y}`;

            // 确保这不是已处理过的已知地点
            if (!placeKeys.includes(coord.name) && !processedCoords.has(uniqueKey)) {
                // 坐标转换：将世界坐标转换为百分比坐标
                const xPercent = ((coord.x + 10000) / 20000) * 100;
                const yPercent = ((coord.y + 8000) / 16000) * 100;

                const isCoordOnly = !coord.name || coord.name.startsWith('坐标点') || coord.name === '坐标' || coord.name === 'Coordinate' || !isNaN(parseFloat(coord.name));
                // 检查此坐标点是否也是当前所处位置：仅基于距离匹配
                // 计算距离，单位为公里，1坐标单位=2公里
                const distance = Math.sqrt(Math.pow(coord.x - (mapData.当前坐标X || 0), 2) + Math.pow(coord.y - (mapData.当前坐标Y || 0), 2)) * 2;
                // 当距离小于等于2公里时，视为当前位置
                const isCurrent = distance <= 2;
                const additionalClass = isCoordOnly ? 'coord-only' : '';

                // 生成坐标键，用于避免重复添加 - 四舍五入到整数以避免浮点精度问题
                const coordKey = `${Math.round(coord.x)},${Math.round(coord.y)}`;

                // 如果这个坐标点同时也是当前所处位置，额外添加一个金色标记
                // 重要：这个要先添加，以确保当前位置标记始终被放置，即使基础坐标点因去重被跳过
                if (isCurrent) {
                    const currentMarkerHtml = `
                        <div class="map-marker current"
                             style="left: ${xPercent}%; top: ${yPercent}%;">
                            <div class="map-marker-label">${coord.name}</div>
                        </div>
                    `;
                    $('#map-canvas').append(currentMarkerHtml);
                    currentLocationAdded = true;
                }

                // 添加基础坐标点标记（蓝色）
                const baseClass = `${additionalClass}`.trim();
                const labelContent = isCoordOnly ? `(${coord.x}, ${coord.y})` : coord.name;

                const markerHtml = `
                    <div class="map-marker ${baseClass}"
                         style="left: ${xPercent}%; top: ${yPercent}%;">
                        <div class="map-marker-label">${labelContent}</div>
                    </div>
                `;
                $('#map-canvas').append(markerHtml);

                processedCoords.add(uniqueKey);

                // 添加到地点列表
                placesHtml += `
                    <div class="place-item">
                        <div class="place-header">
                            <span class="place-name">${coord.name}</span>
                        </div>
                        <div class="info-item">
                            <span class="info-label">坐标</span>
                            <span class="info-value">X: ${coord.x}, Y: ${coord.y}</span>
                        </div>
                    </div>
                `;
            }
        });

        // 检查是否有单独的坐标数组或对象
        if (data.坐标标记 && Array.isArray(data.坐标标记)) {
            data.坐标标记.forEach((coord, index) => {
                if (coord.坐标X !== undefined && coord.坐标Y !== undefined) {
                    const name = coord.名称 || `坐标点${index + 1}`;
                    const x = parseFloat(coord.坐标X) || 0;
                    const y = parseFloat(coord.坐标Y) || 0;

                    const uniqueKey = `${name}_${x}_${y}`;
                    if (!processedCoords.has(uniqueKey)) {
                        // 坐标转换：将世界坐标转换为百分比坐标
                        const xPercent = ((x + 10000) / 20000) * 100;
                        const yPercent = ((y + 8000) / 16000) * 100;

                        const isCoordOnly = !name || name.startsWith('坐标点') || name === '坐标' || name === 'Coordinate' || !isNaN(parseFloat(name));
                        // 检查此坐标点是否也是当前所处位置：仅基于距离匹配
                        // 计算距离，单位为公里，1坐标单位=2公里
                        const distance = Math.sqrt(Math.pow(x - (mapData.当前坐标X || 0), 2) + Math.pow(y - (mapData.当前坐标Y || 0), 2)) * 2;
                        // 当距离小于等于2公里时，视为当前位置
                        const isCurrent = distance <= 2;
                        const additionalClass = isCoordOnly ? 'coord-only' : '';

                        // 生成坐标键，用于避免重复添加 - 四舍五入到整数以避免浮点精度问题
                        const coordKey = `${Math.round(x)},${Math.round(y)}`;

                        // 如果这个坐标点同时也是当前所处位置，额外添加一个金色标记
                        // 重要：这个要先添加，以确保当前位置标记始终被放置，即使基础坐标点因去重被跳过
                        if (isCurrent) {
                            const currentMarkerHtml = `
                                <div class="map-marker current"
                                     style="left: ${xPercent}%; top: ${yPercent}%;">
                                    <div class="map-marker-label">${name}</div>
                                </div>
                            `;
                            $('#map-canvas').append(currentMarkerHtml);
                            currentLocationAdded = true; // 标记已添加
                        }

                        // 添加基础坐标点标记（蓝色）
                        const baseClass = `${additionalClass}`.trim();
                        const labelContent = isCoordOnly ? `(${x}, ${y})` : name;

                        const markerHtml = `
                            <div class="map-marker ${baseClass}"
                                 style="left: ${xPercent}%; top: ${yPercent}%;">
                                <div class="map-marker-label">${labelContent}</div>
                            </div>
                        `;
                        $('#map-canvas').append(markerHtml);

                        processedCoords.add(uniqueKey);

                        // 添加到地点列表
                        placesHtml += `
                            <div class="place-item">
                                <div class="place-header">
                                    <span class="place-name">${name}</span>
                                </div>
                                <div class="info-item">
                                    <span class="info-label">坐标</span>
                                    <span class="info-value">X: ${x}, Y: ${y}</span>
                                </div>
                            </div>
                        `;
                    }
                }
            });
        }

        // 如果没有任何地点或坐标，尝试从其他地方获取纯坐标数据
        if (!placesHtml) {
            // 检查是否有纯坐标数组（比如单独的坐标集合）
            if (Array.isArray(data)) {
                data.forEach((item, index) => {
                    if (item && typeof item === 'object' && item.坐标X !== undefined && item.坐标Y !== undefined) {
                        const name = item.名称 || `坐标点${index + 1}`;
                        const x = parseFloat(item.坐标X) || 0;
                        const y = parseFloat(item.坐标Y) || 0;

                        const uniqueKey = `${name}_${x}_${y}`;
                        if (!processedCoords.has(uniqueKey)) {
                            // 坐标转换：将世界坐标转换为百分比坐标
                            const xPercent = ((x + 10000) / 20000) * 100;
                            const yPercent = ((y + 8000) / 16000) * 100;

                            const isCoordOnly = !name || name.startsWith('坐标点') || name === '坐标' || name === 'Coordinate' || !isNaN(parseFloat(name));
                            // 检查此坐标点是否也是当前所处位置：仅基于距离匹配
                            // 计算距离，单位为公里，1坐标单位=2公里
                            const distance = Math.sqrt(Math.pow(x - (mapData.当前坐标X || 0), 2) + Math.pow(y - (mapData.当前坐标Y || 0), 2)) * 2;
                            // 当距离小于等于2公里时，视为当前位置
                            const isCurrent = distance <= 2;
                            const additionalClass = isCoordOnly ? 'coord-only' : '';

                            // 生成坐标键，用于避免重复添加 - 四舍五入到整数以避免浮点精度问题
                            const coordKey = `${Math.round(x)},${Math.round(y)}`;

                            // 如果这个坐标点同时也是当前所处位置，额外添加一个金色标记
                            // 重要：这个要先添加，以确保当前位置标记始终被放置，即使基础坐标点因去重被跳过
                            if (isCurrent) {
                                const currentMarkerHtml = `
                                    <div class="map-marker current"
                                         style="left: ${xPercent}%; top: ${yPercent}%;">
                                        <div class="map-marker-label">${name}</div>
                                    </div>
                                `;
                                $('#map-canvas').append(currentMarkerHtml);
                                currentLocationAdded = true; // 标记已添加
                            }

                            // 添加基础坐标点标记（蓝色）
                                const baseClass = `${additionalClass}`.trim();
                                const labelContent = isCoordOnly ? `(${x}, ${y})` : name;

                                const markerHtml = `
                                    <div class="map-marker ${baseClass}"
                                         style="left: ${xPercent}%; top: ${yPercent}%;">
                                        <div class="map-marker-label">${labelContent}</div>
                                    </div>
                                `;
                                $('#map-canvas').append(markerHtml);

                            processedCoords.add(uniqueKey);

                            // 添加到地点列表
                            placesHtml += `
                                <div class="place-item">
                                    <div class="place-header">
                                        <span class="place-name">${name}</span>
                                    </div>
                                    <div class="info-item">
                                        <span class="info-label">坐标</span>
                                        <span class="info-value">X: ${x}, Y: ${y}</span>
                                    </div>
                                </div>
                            `;
                        }
                    }
                });
            }
        }

        // 如果所处位置还没有被添加（即不在已知地点中），则单独添加所处位置标记
        if (mapData.所处区域名称 && !currentLocationAdded) {
            // 尝试从已知地点或其他数据源获取所处位置的坐标
            const currentPlace = mapData.已知地点 && mapData.已知地点[mapData.所处区域名称];
            if (currentPlace && currentPlace.坐标X !== undefined && currentPlace.坐标Y !== undefined) {
                const x = currentPlace.坐标X || 0;
                const y = currentPlace.坐标Y || 0;

                // 坐标转换：将世界坐标转换为百分比坐标
                const xPercent = ((x + 10000) / 20000) * 100;
                const yPercent = ((y + 8000) / 16000) * 100;

                const currentMarkerHtml = `
                    <div class="map-marker current"
                         style="left: ${xPercent}%; top: ${yPercent}%;">
                        <div class="map-marker-label">${mapData.所处区域名称}</div>
                    </div>
                `;
                $('#map-canvas').append(currentMarkerHtml);
                currentLocationAdded = true; // 标记已添加
            } else {
                // 如果无法从已知地点获取所处位置坐标，尝试从地图数据中直接获取
                if (mapData.所处坐标X !== undefined && mapData.所处坐标Y !== undefined) {
                    const x = mapData.所处坐标X || 0;
                    const y = mapData.所处坐标Y || 0;

                    // 坐标转换：将世界坐标转换为百分比坐标
                    const xPercent = ((x + 10000) / 20000) * 100;
                    const yPercent = ((y + 8000) / 16000) * 100;

                    const currentMarkerHtml = `
                        <div class="map-marker current"
                             style="left: ${xPercent}%; top: ${yPercent}%;">
                            <div class="map-marker-label">${mapData.所处区域名称}</div>
                        </div>
                    `;
                    $('#map-canvas').append(currentMarkerHtml);
                    currentLocationAdded = true; // 标记已添加
                } else {
                    // 最后的备用方案：如果仍没有找到坐标，使用默认坐标或根据名称查找
                    // 尝试在所有找到的坐标中查找当前区域名称对应的坐标
                    const foundCurrentCoord = foundCoords.find(coord => coord.name.trim() === (mapData.所处区域名称 || '').trim());
                    if (foundCurrentCoord) {
                        const x = foundCurrentCoord.x || 0;
                        const y = foundCurrentCoord.y || 0;

                        // 坐标转换：将世界坐标转换为百分比坐标
                        const xPercent = ((x + 10000) / 20000) * 100;
                        const yPercent = ((y + 8000) / 16000) * 100;

                        const currentMarkerHtml = `
                            <div class="map-marker current"
                                 style="left: ${xPercent}%; top: ${yPercent}%;">
                                <div class="map-marker-label">${mapData.所处区域名称}</div>
                            </div>
                        `;
                        $('#map-canvas').append(currentMarkerHtml);
                        currentLocationAdded = true; // 标记已添加
                    } else {
                        // 如果仍然找不到坐标，但有所处区域名称，至少显示一个默认位置的标记
                        console.log(`Current location '${mapData.所处区域名称}' coordinates not found, adding fallback marker.`);
                        // 添加一个默认位置的标记 as fallback - using center of map
                        const currentMarkerHtml = `
                            <div class="map-marker current"
                                 style="left: 50%; top: 50%;">
                                <div class="map-marker-label">${mapData.所处区域名称}</div>
                            </div>
                        `;
                        $('#map-canvas').append(currentMarkerHtml);
                        currentLocationAdded = true; // 标记已添加
                    }
                }
            }
        }

        if (placesHtml) {
            $('#places-section').html(placesHtml);
        } else {
            $('#places-section').html('<div class="empty-state">暂无地点标记</div>');
        }

    } catch (error) {
        console.error('渲染地图失败:', error);
    }
}

