            const breakthrough = vitals.突破灵力 || { 当前: 0, 上限: 100 };
            const karma = (vitals.业力 !== undefined && vitals.业力 !== null) ? Number(vitals.业力) : 0;

            // mode: 'percent' 显示百分比条; 'exact' 显示准确数值(当前/上限)
            const rows = [
                { key: 'hp', label: '血量', cur: Number(hp.当前) || 0, max: (hp.上限 === undefined || hp.上限 === null) ? 100 : Number(hp.上限), mode: 'percent' },
                { key: 'mp', label: '灵力', cur: Number(mp.当前) || 0, max: (mp.上限 === undefined || mp.上限 === null) ? 100 : Number(mp.上限), mode: 'exact' },
                { key: 'spirit', label: '神识', cur: Number(spirit.当前) || 0, max: (spirit.上限 === undefined || spirit.上限 === null) ? 100 : Number(spirit.上限), mode: 'percent' },
                { key: 'breakthrough', label: '突破灵力', cur: Number(breakthrough.当前) || 0, max: (breakthrough.上限 === undefined || breakthrough.上限 === null) ? 100 : Number(breakthrough.上限), mode: 'exact' },
            ];

            let html = '';
            rows.forEach(row => {
                const isInfinite = row.max < 0; // -1(或任意负数)代表无穷/无上限
                let barPct, valueText;
                if (isInfinite) {
                    barPct = 100;
                    valueText = row.mode === 'percent' ? '∞ (无上限)' : `${formatVitalNum(row.cur)} (无上限)`;
                } else if (row.max <= 0) {
                    barPct = 0;
                    valueText = row.mode === 'percent' ? '0%' : `${formatVitalNum(row.cur)} / 0`;
                } else {
                    barPct = Math.min(100, Math.max(0, Math.round(row.cur / row.max * 100)));
                    valueText = row.mode === 'percent' ? `${barPct}%` : `${formatVitalNum(row.cur)} / ${formatVitalNum(row.max)}`;
                }
                html += `
                    <div class="vital-row">
                        <div class="vital-row-top">
                            <span class="vital-row-label"><span class="vital-dot ${row.key}"></span>${row.label}</span>
                            <span class="vital-row-value">${valueText}</span>
                        </div>
                        <div class="vital-bar-track"><div class="vital-bar-fill ${row.key}" style="width:${barPct}%;"></div></div>
                    </div>
                `;
            });

            // 业力用居中双向进度条展示，范围 -1000~1000，显示准确数值
            const karmaPct = Math.min(100, Math.max(0, Math.round((karma + 1000) / 2000 * 100)));
            html += `
                <div class="vital-row">
                    <div class="vital-row-top">
                        <span class="vital-row-label"><span class="vital-dot karma"></span>业力</span>
                        <span class="vital-row-value">${formatVitalNum(karma)}</span>
