    /* ==================== MVU 写入与交互功能（推进时辰/采集/仓库转移） ==================== */

    function showNotification(message, type = 'success') {
        try {
            const div = document.createElement('div');
            div.className = 'notification ' + type;
            div.textContent = message;
            document.body.appendChild(div);
            setTimeout(() => { div.remove(); }, 3000);
        } catch (e) {
            console.error('通知显示失败:', e);
        }
    }

    async function ensureMvuReady() {
        if (typeof Mvu !== 'undefined') return true;
        try {
            if (typeof waitGlobalInitialized === 'function') {
                await waitGlobalInitialized('Mvu');
            }
        } catch (e) { /* 忽略，走下面的轮询兜底 */ }
        let tries = 0;
        while (typeof Mvu === 'undefined' && tries < 30) {
            await new Promise(r => setTimeout(r, 100));
            tries++;
        }
        return typeof Mvu !== 'undefined';
    }

    function getMsgId() {
        try {
            if (typeof getCurrentMessageId === 'function') return getCurrentMessageId();
        } catch (e) { /* 忽略 */ }
        return 'latest';
    }

    /**
     * 读取当前MVU数据、执行mutatorFn变更、写回并刷新界面。
     * mutatorFn(statData) 直接修改 statData，返回 false 代表条件不满足、不需要保存。
     */
    async function withMvuData(mutatorFn, successMsg) {
        const ready = await ensureMvuReady();
        if (!ready) {
            showNotification('MVU尚未就绪，请稍后重试', 'error');
            return false;
        }
        try {
            const messageId = getMsgId();
            const mvuData = await Mvu.getMvuData({ type: 'message', message_id: messageId });
            if (!mvuData || !mvuData.stat_data) {
                showNotification('未能读取到变量数据', 'error');
                return false;
            }
            const result = mutatorFn(mvuData.stat_data);
            if (result === false) return false;
            await Mvu.replaceMvuData(mvuData, { type: 'message', message_id: messageId });
            renderAllPanels();
            if (typeof renderWanyuSystem === 'function') renderWanyuSystem();
            if (successMsg) showNotification(successMsg, 'success');
            return true;
        } catch (error) {
            console.error('MVU写入失败:', error);
            showNotification('操作失败: ' + (error && error.message ? error.message : error), 'error');
            return false;
        }
    }

    /**
     * 采集灵田：成熟后将结构化产出写入储物囊，并把该灵田重置为空闲状态
     */
    window.harvestField = async function(fieldName) {
        await withMvuData((stat) => {
            const field = _.get(stat, ['洞府信息', '灵田', fieldName]);
            if (!field) {
                showNotification('未找到该灵田', 'error');
                return false;
            }
            if (Number(field.剩余时辰) > 0 || !field.种植灵植 || field.种植灵植 === '未种植') {
                showNotification('该灵田尚未成熟', 'error');
                return false;
            }
            const outputName = field.产出物品 || field.种植灵植;
            const outputQty = Number(field.产出数量) || 1;
            const outputGrade = field.产出品阶 || field.品阶 || '';

            if (outputName) {
                _.set(stat, ['主角信息', '持有物品', '储物囊'], _.get(stat, ['主角信息', '持有物品', '储物囊'], {}));
                const storage = stat.主角信息.持有物品.储物囊;
                if (storage[outputName]) {
                    storage[outputName].数量 = (Number(storage[outputName].数量) || 0) + outputQty;
                } else {
                    storage[outputName] = {
                        类型: '灵植/药材',
                        品阶: outputGrade,
                        数量: outputQty,
                        描述: `采收自灵田【${fieldName}】的产出`,
                        来源: `洞府灵田-${fieldName}`,
                        功能: '',
                        使用方法: '',
                        外观描述: '',
                        市场价值: '',
                        稀有度: ''
                    };
                }
            }

            // 清空该灵田为空闲状态
            field.种植灵植 = '未种植';
            field.品阶 = '无';
            field.预计成熟时间 = '-';
            field.预计产量 = '-';
            field.总需时辰 = 0;
            field.剩余时辰 = 0;
            field.产出物品 = '';
            field.产出数量 = 0;
            field.产出品阶 = '';

            return true;
        }, '采集成功，已放入储物囊');
    };

    /**
     * 在【储物囊】与洞府【仓库】之间整份转移物品
     */
    window.moveItemBetween = async function(fromKey, toKey, itemName) {
        await withMvuData((stat) => {
            _.set(stat, ['主角信息', '持有物品', '储物囊'], _.get(stat, ['主角信息', '持有物品', '储物囊'], {}));
            _.set(stat, ['洞府信息', '仓库'], _.get(stat, ['洞府信息', '仓库'], {}));

            const fromContainer = (fromKey === '储物囊') ? stat.主角信息.持有物品.储物囊 : stat.洞府信息.仓库;
            const toContainer = (toKey === '储物囊') ? stat.主角信息.持有物品.储物囊 : stat.洞府信息.仓库;

            if (!fromContainer || !fromContainer[itemName]) {
                showNotification('未找到该物品', 'error');
                return false;
            }

            const item = fromContainer[itemName];
            if (toContainer[itemName]) {
                toContainer[itemName].数量 = (Number(toContainer[itemName].数量) || 0) + (Number(item.数量) || 1);
            } else {
                toContainer[itemName] = _.cloneDeep(item);
            }
            delete fromContainer[itemName];

            return true;
        }, `已将【${itemName}】转移`);
    };

