        /* 转换H/S/B为CSS滤镜字符串 */
        function makeFilter(hue, saturation, brightness) {
          const h = Number(hue) || 0;
          const s = Number(saturation) || 1;
          const b = Number(brightness) || 1;
          // 确保值在合理范围内
          const safeS = Math.max(0, Math.min(3, s));
          const safeB = Math.max(0, Math.min(3, b));
          return 'hue-rotate(' + h + 'deg) saturate(' + safeS + ') brightness(' + safeB + ')';
        }

        /* 从头像对象构建滤镜 */
        function buildAvatarFilters(avatar) {
          const colors = avatar && avatar.colors ? avatar.colors : {};
          const skin = colors.skin || {};
          const hair = colors.hair || {};
          const eyes = colors.eyes || {};
          const mouth = colors.mouth || {};

          const skinFilter = makeFilter(skin.hue, skin.saturation, skin.brightness);
          const hairFilter = makeFilter(hair.hue, hair.saturation, hair.brightness);
          const eyeFilter  = makeFilter(eyes.hue, eyes.saturation, eyes.brightness);
          const mouthFilter = makeFilter(mouth.hue, mouth.saturation, mouth.brightness);

          return {
            skin: skinFilter,
            hair: hairFilter,
            eyes: eyeFilter,
            skinShadow: mouthFilter,
            none: 'none'
          };
        }

