            }
          ];

          /* 可选：渲染附加图层 */
          const extraLayers = _.get(avatar, '附加图层', {});
          Object.keys(extraLayers).forEach(function (name) {
            layers.push({
              key: name,
              folder: 'accessory',
              filterKey: 'none'
            });
          });

          layers.forEach(function (layerDef) {
            var indexValue;
            if (layerDef.key === '后发') {
              indexValue = avatar.后发;
            } else if (layerDef.key === '前发') {
              indexValue = avatar.前发;
            } else if (layerDef.key === '脸型') {
              indexValue = avatar.脸型;
            } else if (layerDef.key === '衣服') {
              indexValue = avatar.衣服;
            } else {
              indexValue = extraLayers[layerDef.key];
            }

            const src = getAvatarLayerSrc(layerDef.folder, indexValue);
            if (!src) {
              return;
            }

            const $layer = $('<div class="avatar-layer"></div>');
            $layer.css('background-image', 'url("' + src + '")');

            const filterKey = layerDef.filterKey || 'none';
            const filterValue = filters[filterKey] || 'none';
            $layer.css('filter', filterValue);

            $container.append($layer);
          });
        }

        /* ==================== 初始化 ==================== */
        async function init() {
            try {
                // 尝试等待Mvu全局对象初始化
                await waitGlobalInitialized('Mvu');

                // 渲染万域系统（MVU方式）
                renderWanyuSystem();

                // 监听MVU变量变化，实时更新万域系统
                window.addEventListener('mvu:variablesUpdated', function() {
                    renderWanyuSystem();
                    renderAllPanels();
                });
            } catch (error) {
                console.error('等待Mvu初始化失败:', error);
                // 注意：这里不再回退解析正文，正文解析放到 try/catch 外统一执行
            }

            // 不管 MVU 是否成功，其他面板和正文都要渲染
            renderAllPanels();
            extractMainTextModule();
            parseMainText();

            $('.nav-button').on('click', function() {
                const target = $(this).data('target');
                showPanel(target);
                $('.nav-button').removeClass('active');
                $(this).addClass('active');
            });

            $('.nav-button').first().addClass('active');

            /* 设置滑块事件（带持久化） */
            const savedColorTheme = localStorage.getItem('wanyu-colorTheme') || '#1a1a2e';
            const colorPicker = document.getElementById('color-picker');
            if (colorPicker) {
                colorPicker.value = savedColorTheme;
                applyColorTheme(savedColorTheme);
                colorPicker.addEventListener('input', function() {
                    applyColorTheme(this.value);
                });
            }

            const savedOpacity = parseInt(localStorage.getItem('wanyu-opacity'), 10);
            const initialOpacity = isNaN(savedOpacity) ? 100 : savedOpacity;
            $('#opacity-slider').val(initialOpacity);
            applyOpacity(initialOpacity);
            $('#opacity-slider').on('input', function() {
                applyOpacity(this.value);
            });

            const savedFontSize = parseInt(localStorage.getItem('wanyu-fontSize'), 10);
            const initialFontSize = isNaN(savedFontSize) ? 14 : savedFontSize;
            $('#font-size-slider').val(initialFontSize);
            applyFontSize(initialFontSize);
            $('#font-size-slider').on('input', function() {
                applyFontSize(this.value);
            });

            const savedBrightness = parseInt(localStorage.getItem('wanyu-brightness'), 10);
            const initialBrightness = isNaN(savedBrightness) ? 100 : savedBrightness;
            $('#brightness-slider').val(initialBrightness);
            applyBrightness(initialBrightness);
            $('#brightness-slider').on('input', function() {
                applyBrightness(this.value);
            });

            const savedBgImage = localStorage.getItem('wanyu-backgroundImage') || '';
            const bgInput = document.getElementById('bg-image-url');
            if (bgInput) {
                bgInput.value = savedBgImage;
                if (savedBgImage) {
                    applyBackgroundImage(savedBgImage);
                }
                bgInput.addEventListener('keypress', function(e) {
                    if (e.key === 'Enter') {
                        applyBackgroundImage(this.value);
                    }
                });
                bgInput.addEventListener('blur', function() {
                    applyBackgroundImage(this.value);
                });
            }

            const savedNormalTextColor = localStorage.getItem('wanyu-normalTextColor') || '#EFF1FE';
            const normalTextPicker = document.getElementById('normal-text-picker');
            if (normalTextPicker) {
                normalTextPicker.value = savedNormalTextColor;
                applyNormalTextColor(savedNormalTextColor);
                normalTextPicker.addEventListener('input', function() {
                    applyNormalTextColor(this.value);
                });
            }

            const savedHighlightTextColor = localStorage.getItem('wanyu-highlightTextColor') || '#4ECDC4';
            const highlightTextPicker = document.getElementById('highlight-text-picker');
            if (highlightTextPicker) {
                highlightTextPicker.value = savedHighlightTextColor;
                applyHighlightTextColor(savedHighlightTextColor);
                highlightTextPicker.addEventListener('input', function() {
                    applyHighlightTextColor(this.value);
                });
            }

            // 头像开关设置
            const savedAvatarEnabled = localStorage.getItem('wanyu-avatarEnabled') === 'true';
            const avatarToggle = document.getElementById('avatar-toggle');
            if (avatarToggle) {
                avatarToggle.checked = savedAvatarEnabled;
                avatarToggle.addEventListener('change', function() {
                    localStorage.setItem('wanyu-avatarEnabled', this.checked.toString());
                    // 重新渲染社交网络以更新头像显示
                    renderAllPanels();
                });
            }

            // 八卦面板开关设置（默认开启）
            const savedGossipEnabled = localStorage.getItem('wanyu-gossipEnabled') !== 'false';
            const gossipToggle = document.getElementById('gossip-toggle');
            if (gossipToggle) {
                gossipToggle.checked = savedGossipEnabled;
                gossipToggle.addEventListener('change', function() {
                    localStorage.setItem('wanyu-gossipEnabled', this.checked.toString());
                    applyGossipVisibility(this.checked);
                });
            }
            applyGossipVisibility(savedGossipEnabled);
        }

        $(document).ready(function() {
            init();
        });

        /* ==================== 全局函数 ==================== */
        window.showPanel = function(panelId) {
            $('.content-panel').removeClass('active-panel');
            $(`#${panelId}`).addClass('active-panel');
        };

        window.applyGossipVisibility = function(enabled) {
            const $btn = $('.nav-button[data-target="gossip-panel"]');
            if (enabled) {
                $btn.show();
            } else {
                $btn.hide();
                // 若八卦面板正处于激活状态，关闭后自动切换回核心正文
                if ($('#gossip-panel').hasClass('active-panel')) {
                    showPanel('main-text-panel');
                    $('.nav-button').removeClass('active');
                    $('.nav-button[data-target="main-text-panel"]').addClass('active');
                }
            }
        };

        window.toggleCollapsible = function(header) {
            const $header = $(header);
            const $content = $header.next('.collapsible-content');
            $header.toggleClass('expanded');
            $content.toggleClass('expanded');
        };

        window.resetSettings = function() {
            try {
                localStorage.removeItem('wanyu-opacity');
                localStorage.removeItem('wanyu-fontSize');
                localStorage.removeItem('wanyu-brightness');
                localStorage.removeItem('wanyu-colorTheme');
                localStorage.removeItem('wanyu-backgroundImage');
                localStorage.removeItem('wanyu-normalTextColor');
                localStorage.removeItem('wanyu-highlightTextColor');
                localStorage.removeItem('wanyu-avatarEnabled');
                localStorage.removeItem('wanyu-gossipEnabled');
            } catch (e) {}
            $('#opacity-slider').val(100);
            $('#font-size-slider').val(14);
            $('#brightness-slider').val(100);
            const avatarToggle = document.getElementById('avatar-toggle');
            if (avatarToggle) {
                avatarToggle.checked = false;
            }
            const gossipToggle = document.getElementById('gossip-toggle');
            if (gossipToggle) {
                gossipToggle.checked = true;
            }
            applyGossipVisibility(true);
            applyOpacity(100);
            applyFontSize(14);
            applyBrightness(100);
            applyColorTheme('#1a1a2e');
            applyBackgroundImage('');
            applyNormalTextColor('#EFF1FE');
            applyHighlightTextColor('#4ECDC4');
            // 重新渲染所有面板以更新头像显示
            renderAllPanels();
        };

        const ARCHIVE_KEY = 'xiuxian_archives';

        window.saveArchive = function() {
            const archiveName = prompt('请输入存档名称:');
            if (!archiveName) return;

            const settings = {
                fontSize: localStorage.getItem('wanyu-fontSize') || 14,
                brightness: localStorage.getItem('wanyu-brightness') || 100,
                opacity: localStorage.getItem('wanyu-opacity') || 100,
                backgroundImage: localStorage.getItem('wanyu-backgroundImage') || '',
                colorTheme: localStorage.getItem('wanyu-colorTheme') || '#1a1a2e',
                normalTextColor: localStorage.getItem('wanyu-normalTextColor') || '#EFF1FE',
                highlightTextColor: localStorage.getItem('wanyu-highlightTextColor') || '#4ECDC4',
                avatarEnabled: localStorage.getItem('wanyu-avatarEnabled') || 'false',
                gossipEnabled: localStorage.getItem('wanyu-gossipEnabled') !== 'false' ? 'true' : 'false'
            };

            const archives = JSON.parse(localStorage.getItem(ARCHIVE_KEY) || '{}');
            archives[archiveName] = {
                name: archiveName,
                settings: settings,
                timestamp: new Date().toISOString()
            };

            localStorage.setItem(ARCHIVE_KEY, JSON.stringify(archives));
            alert(`存档 "${archiveName}" 已保存`);
            updateArchiveList();
        };

        window.loadArchive = function(archiveName) {
            const archives = JSON.parse(localStorage.getItem(ARCHIVE_KEY) || '{}');
            const archive = archives[archiveName];

            if (!archive) {
                alert('存档不存在');
                return;
            }

            const settings = archive.settings;

            localStorage.setItem('wanyu-fontSize', settings.fontSize);
            localStorage.setItem('wanyu-brightness', settings.brightness);
            localStorage.setItem('wanyu-opacity', settings.opacity);
            localStorage.setItem('wanyu-backgroundImage', settings.backgroundImage);
            localStorage.setItem('wanyu-colorTheme', settings.colorTheme);
            localStorage.setItem('wanyu-normalTextColor', settings.normalTextColor);
            localStorage.setItem('wanyu-highlightTextColor', settings.highlightTextColor);
            localStorage.setItem('wanyu-avatarEnabled', settings.avatarEnabled);
            localStorage.setItem('wanyu-gossipEnabled', settings.gossipEnabled !== undefined ? settings.gossipEnabled : 'true');

            $('#font-size-slider').val(settings.fontSize);
            $('#brightness-slider').val(settings.brightness);
            $('#opacity-slider').val(settings.opacity);
            const avatarToggle = document.getElementById('avatar-toggle');
            if (avatarToggle) {
                avatarToggle.checked = settings.avatarEnabled === 'true';
            }
            const gossipToggle = document.getElementById('gossip-toggle');
            if (gossipToggle) {
                gossipToggle.checked = settings.gossipEnabled !== 'false';
            }
            applyGossipVisibility(settings.gossipEnabled !== 'false');

            applyFontSize(settings.fontSize);
            applyBrightness(settings.brightness);
            applyOpacity(settings.opacity);

            if (settings.backgroundImage) {
                document.body.style.backgroundImage = `url(${settings.backgroundImage})`;
            } else {
                document.body.style.backgroundImage = '';
            }

            applyColorTheme(settings.colorTheme);
            applyNormalTextColor(settings.normalTextColor);
            applyHighlightTextColor(settings.highlightTextColor);

            alert(`已加载存档 "${archiveName}"`);
        };

        window.overwriteArchive = function(archiveName) {
            if (!confirm(`确定要覆盖存档 "${archiveName}" 吗？`)) return;

            const settings = {
                fontSize: localStorage.getItem('wanyu-fontSize') || 14,
                brightness: localStorage.getItem('wanyu-brightness') || 100,
                opacity: localStorage.getItem('wanyu-opacity') || 100,
                backgroundImage: localStorage.getItem('wanyu-backgroundImage') || '',
                colorTheme: localStorage.getItem('wanyu-colorTheme') || '#1a1a2e',
                normalTextColor: localStorage.getItem('wanyu-normalTextColor') || '#EFF1FE',
                highlightTextColor: localStorage.getItem('wanyu-highlightTextColor') || '#4ECDC4',
                avatarEnabled: localStorage.getItem('wanyu-avatarEnabled') || 'false',
                gossipEnabled: localStorage.getItem('wanyu-gossipEnabled') !== 'false' ? 'true' : 'false'
            };

            const archives = JSON.parse(localStorage.getItem(ARCHIVE_KEY) || '{}');
            archives[archiveName] = {
                name: archiveName,
                settings: settings,
                timestamp: new Date().toISOString()
            };

            localStorage.setItem(ARCHIVE_KEY, JSON.stringify(archives));
            alert(`存档 "${archiveName}" 已覆盖`);
            updateArchiveList();
        };

        window.renameArchive = function(oldName) {
            const newName = prompt('请输入新的存档名称:', oldName);
            if (!newName || newName === oldName) return;

            const archives = JSON.parse(localStorage.getItem(ARCHIVE_KEY) || '{}');
            const archive = archives[oldName];

            if (!archive) {
                alert('存档不存在');
                return;
            }

            delete archives[oldName];
            archive.name = newName;
            archives[newName] = archive;

            localStorage.setItem(ARCHIVE_KEY, JSON.stringify(archives));
            alert(`存档已重命名为 "${newName}"`);
            updateArchiveList();
        };

        window.deleteArchive = function(archiveName) {
            if (!confirm(`确定要删除存档 "${archiveName}" 吗？此操作不可撤销。`)) return;

            const archives = JSON.parse(localStorage.getItem(ARCHIVE_KEY) || '{}');
            delete archives[archiveName];

            localStorage.setItem(ARCHIVE_KEY, JSON.stringify(archives));
            alert(`存档 "${archiveName}" 已删除`);
            updateArchiveList();
        };

        function applyColorTheme(color) {
            const colorPreview = document.getElementById('color-preview');
            const colorName = document.getElementById('color-name');
            const colorValue = document.getElementById('color-value');

            if (colorPreview) {
                colorPreview.style.background = color;
                colorPreview.textContent = getColorName(color);
            }

            if (colorName) {
                colorName.textContent = getColorName(color);
            }

            if (colorValue) {
                colorValue.textContent = color.toUpperCase();
            }

            const opacity = parseInt(localStorage.getItem('wanyu-opacity') || 100, 10) / 100;
            const rgbaColor = hexToRgba(color, opacity * 0.8);

            document.querySelectorAll('.left-sidebar').forEach(el => {
                el.style.backgroundColor = rgbaColor;
            });

            document.querySelectorAll('.content-panel').forEach(el => {
                el.style.backgroundColor = rgbaColor;
            });

            document.querySelectorAll('.panel').forEach(el => {
                el.style.backgroundColor = rgbaColor;
            });

            try {
                localStorage.setItem('wanyu-colorTheme', color);
            } catch (e) {}
        }

        function applyNormalTextColor(color) {
            const colorPreview = document.getElementById('normal-text-preview');
            const colorName = document.getElementById('normal-text-name');
            const colorValue = document.getElementById('normal-text-value');

            if (colorPreview) {
                colorPreview.style.background = color;
                colorPreview.textContent = getColorName(color);
            }

            if (colorName) {
                colorName.textContent = getColorName(color);
            }

            if (colorValue) {
                colorValue.textContent = color.toUpperCase();
            }

            document.querySelectorAll('.info-value, .status-value, .narrative-content, .info-item, .value-item, .description-content, .event-description, .task-description, .empty-state, .item-name, .item-description, .item-meta, .section-content, .status-label').forEach(element => {
                element.style.setProperty('color', color, 'important');
            });

            try {
                localStorage.setItem('wanyu-normalTextColor', color);
            } catch (e) {}
        }

        function applyHighlightTextColor(color) {
            const colorPreview = document.getElementById('highlight-text-preview');
            const colorName = document.getElementById('highlight-text-name');
            const colorValue = document.getElementById('highlight-text-value');

            if (colorPreview) {
                colorPreview.style.background = color;
                colorPreview.textContent = getColorName(color);
            }

            if (colorName) {
                colorName.textContent = getColorName(color);
            }

            if (colorValue) {
                colorValue.textContent = color.toUpperCase();
            }

            document.querySelectorAll('.section-title, .subsection-title, .panel-title, .character-name, .item-name, .skill-value, .event-title, .task-title, .item-title, .aura-value, .event-date, .task-date, .item-grade, .item-status, .progress-label, .attribute-label, .skill-label, .spirit-root-label, .combat-label, .person-name, .description-label, .value-label, .resource-name, .facility-name, .collapsible-title').forEach(element => {
                element.style.setProperty('color', color, 'important');
            });

            try {
                localStorage.setItem('wanyu-highlightTextColor', color);
            } catch (e) {}
        }

        function applyBackgroundImage(url) {
            const defaultBg = 'https://pic.itxiaohui.top/20250829/98e1e1ebe5ceae99dd18d9b936835e5d.png';
            const imageUrl = url && url.trim() !== '' ? url : defaultBg;

            document.body.style.backgroundImage = `url('${imageUrl}')`;

            try {
                localStorage.setItem('wanyu-backgroundImage', url);
            } catch (e) {}
        }

        function updateArchiveList() {
            const archiveList = document.getElementById('archive-list');
            if (!archiveList) return;

            const archives = JSON.parse(localStorage.getItem(ARCHIVE_KEY) || '{}');
            const archiveNames = Object.keys(archives);

            if (archiveNames.length === 0) {
                archiveList.innerHTML = '<div class="no-archives">暂无存档</div>';
                return;
            }

            let html = '';
            archiveNames.forEach(name => {
                const archive = archives[name];
                const date = new Date(archive.timestamp).toLocaleString('zh-CN');
                const escapedName = escapeJsString(name);

                html += `
                    <div class="archive-item">
                        <div class="archive-info">
                            <div class="archive-name">${escapeHtml(name)}</div>
                            <div class="archive-date">${date}</div>
                        </div>
                        <div class="archive-actions">
                            <button class="archive-btn load-btn" onclick="loadArchive('${escapedName}')">加载</button>
                            <button class="archive-btn overwrite-btn" onclick="overwriteArchive('${escapedName}')">覆盖</button>
                            <button class="archive-btn rename-btn" onclick="renameArchive('${escapedName}')">重命名</button>
                            <button class="archive-btn delete-btn" onclick="deleteArchive('${escapedName}')">删除</button>
                        </div>
                    </div>
                `;
            });

            archiveList.innerHTML = html;
        }

        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }

        function escapeJsString(text) {
            return text.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/"/g, '\\"').replace(/\n/g, '\\n').replace(/\r/g, '\\r');
        }

        window.openArchiveManager = function() {
            const modal = document.getElementById('archive-manager');
            if (modal) {
                modal.style.display = 'flex';
                updateArchiveList();
            }
        };

        window.closeArchiveManager = function() {
            const modal = document.getElementById('archive-manager');
            if (modal) {
                modal.style.display = 'none';
            }
        };
    </script>
</head>

