    /* ==================== DLC选择器页面 ==================== */
.dlc-page-wrapper {
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    padding: 15px 30px 20px;
}

.dlc-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
    flex-shrink: 0;
}

.dlc-main-title {
    font-size: 1.8rem;
    color: #4ECDC4;
    text-shadow: 0 0 15px rgba(78, 205, 196, 0.4);
    letter-spacing: 3px;
}

.dlc-reset-btn {
    padding: 6px 16px;
    background: rgba(180, 70, 70, 0.15);
    border: 1px solid rgba(180, 70, 70, 0.4);
    color: #d09090;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
    transition: all 0.25s;
}

.dlc-reset-btn:hover {
    background: rgba(180, 70, 70, 0.35);
    color: #f0c0c0;
}

/* 导航标签 */
.dlc-tab-bar {
    display: flex;
    margin-bottom: 10px;
    border-bottom: 1px solid rgba(78, 205, 196, 0.15);
    flex-shrink: 0;
}

.dlc-tab-item {
    flex: 1;
    padding: 9px 0;
    background: transparent;
    border: none;
    border-bottom: 2px solid transparent;
    color: #8895B1;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.25s;
    text-align: center;
    letter-spacing: 1px;
}

.dlc-tab-item:hover {
    color: #BCC2D7;
    background: rgba(78, 205, 196, 0.04);
}

.dlc-tab-item.on {
    color: #4ECDC4;
    border-bottom-color: #4ECDC4;
}

/* 状态预览栏 */
.dlc-status-bar {
    display: flex;
    gap: 15px;
    padding: 8px 14px;
    background: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(78, 205, 196, 0.12);
    border-radius: 5px;
    margin-bottom: 12px;
    align-items: center;
    flex-wrap: wrap;
    flex-shrink: 0;
}

.status-chip {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 0.82rem;
}

.status-chip .s-label {
    color: #7884a0;
}

.status-chip .s-val {
    color: #4ECDC4;
    font-weight: 600;
}

.status-sep {
    color: rgba(78, 205, 196, 0.2);
    font-size: 0.7rem;
}

/* 内容区域 */
.dlc-body {
    flex: 1;
    overflow-y: auto;
    overflow-x: hidden;
    position: relative;
}

.dlc-body::-webkit-scrollbar {
    width: 5px;
}

.dlc-body::-webkit-scrollbar-track {
    background: transparent;
}

.dlc-body::-webkit-scrollbar-thumb {
    background: rgba(78, 205, 196, 0.25);
    border-radius: 3px;
}

.dlc-sheet {
    display: none;
}

.dlc-sheet.on {
    display: block;
    animation: dlcSheetIn 0.3s ease;
}

.dlc-subnav {
    display: flex;
    gap: 8px;
    margin-bottom: 12px;
    padding: 8px 0;
    border-bottom: 1px solid rgba(78, 205, 196, 0.15);
}

.dlc-subnav-item {
    padding: 6px 12px;
    background: rgba(0, 0, 0, 0.2);
    border: 1px solid rgba(136, 149, 177, 0.2);
    border-radius: 4px;
    color: #8895B1;
    font-size: 0.85rem;
    cursor: pointer;
    transition: all 0.2s;
}

.dlc-subnav-item:hover {
    background: rgba(78, 205, 196, 0.08);
    border-color: rgba(78, 205, 196, 0.3);
    color: #BCC2D7;
}

.dlc-subnav-item.on {
    background: rgba(78, 205, 196, 0.15);
    border-color: #4ECDC4;
    color: #4ECDC4;
}

.dlc-subcontent {
    min-height: 200px;
}

.dlc-subsheet {
    display: none;
}

.dlc-subsheet.on {
    display: block;
    animation: dlcSheetIn 0.3s ease;
}

@keyframes dlcSheetIn {
    from {
        opacity: 0;
        transform: translateY(6px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* 难度卡片 */
.diff-list {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 8px;
}

.diff-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 10px 14px;
    background: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(136, 149, 177, 0.15);
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.25s;
    user-select: none;
}

.diff-item:hover {
    background: rgba(78, 205, 196, 0.08);
    border-color: rgba(78, 205, 196, 0.25);
}

.diff-item.picked {
    background: rgba(78, 205, 196, 0.12);
    border-color: #4ECDC4;
    box-shadow: 0 0 10px rgba(78, 205, 196, 0.15), inset 0 0 8px rgba(78, 205, 196, 0.05);
}

.diff-item.picked .d-name::before {
    content: '✦ ';
    color: #4ECDC4;
}

.diff-item .d-stars {
    font-size: 0.75rem;
    color: #e0b850;
    min-width: 80px;
    letter-spacing: -1px;
}

.diff-item .d-body {
    flex: 1;
}

.diff-item .d-name {
    font-size: 0.95rem;
    color: #EFF1FE;
    font-weight: 600;
}

.diff-item .d-note {
    font-size: 0.75rem;
    color: #7884a0;
    margin-top: 2px;
}

/* NPC网格 */
.npc-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
}

.npc-card {
    background: rgba(0, 0, 0, 0.25);
    border: 1px solid rgba(136, 149, 177, 0.15);
    border-radius: 7px;
    padding: 12px 14px;
    transition: all 0.25s;
}

.npc-card:hover {
    border-color: rgba(78, 205, 196, 0.25);
    background: rgba(0, 0, 0, 0.35);
}

.npc-card .nc-name {
    font-size: 1rem;
    color: #4ECDC4;
    font-weight: 600;
}

.npc-card .nc-trait {
    font-size: 0.8rem;
    color: #7884a0;
    margin: 2px 0 8px;
}


.npc-controls {
    display: flex;
    gap: 8px;
    margin-bottom: 12px;
    padding: 8px;
    background: rgba(0, 0, 0, 0.2);
    border-radius: 6px;
}

.npc-controls .npc-btn {
    flex: 1;
    padding: 6px 10px;
    font-size: 0.8rem;
    background: rgba(136, 149, 177, 0.15);
    border: 1px solid rgba(136, 149, 177, 0.25);
    border-radius: 4px;
    color: #BCC2D7;
    cursor: pointer;
    transition: all 0.2s;
}

.npc-controls .npc-btn:hover {
    background: rgba(136, 149, 177, 0.25);
    border-color: rgba(136, 149, 177, 0.4);
}

.npc-controls .npc-btn:active {
    transform: translateY(1px);
}

.nc-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 3px 0;
}

.nc-row .nc-label {
    font-size: 0.85rem;
    color: #BCC2D7;
}

/* 滑块开关 */
.sw-wrap {
    position: relative;
    width: 38px;
    height: 20px;
    display: inline-block;
}

.sw-wrap input {
    opacity: 0;
    width: 0;
    height: 0;
    position: absolute;
}

.sw-track {
    position: absolute;
    inset: 0;
    background: rgba(80, 80, 80, 0.35);
    border: 1px solid rgba(136, 149, 177, 0.25);
    border-radius: 10px;
    cursor: pointer;
    transition: all 0.25s;
}

.sw-track::after {
    content: '';
    position: absolute;
    width: 14px;
    height: 14px;
    left: 2px;
    bottom: 2px;
    background: #7884a0;
    border-radius: 50%;
    transition: all 0.25s;
}

.sw-wrap input:checked + .sw-track {
    background: rgba(78, 205, 196, 0.25);
    border-color: rgba(78, 205, 196, 0.45);
}

.sw-wrap input:checked + .sw-track::after {
    transform: translateX(18px);
    background: #4ECDC4;
}

/* DLC内容卡片 */
.dlc-group {
    margin-bottom: 18px;
}

