    dialog.style.cssText = 'background:#1a1f2e;border:2px solid #4ECDC4;border-radius:12px;padding:25px;width:600px;max-width:90%;box-shadow:0 8px 32px rgba(0,0,0,0.5);';

    dialog.innerHTML = `
        <div style="font-size:20px;color:#4ECDC4;margin-bottom:20px;font-weight:700;border-bottom:2px solid rgba(78,205,196,0.3);padding-bottom:12px;">✎ 编辑自定义选项</div>
