            <input type="text" id="editOptionName" value="${option.name.replace(/"/g, '&quot;')}" 
                   style="width:100%;background:rgba(0,0,0,0.5);border:1px solid rgba(136,149,177,0.5);border-radius:6px;padding:12px;color:#EFF1FE;font-size:14px;box-sizing:border-box;"
                   placeholder="请输入选项名称">
        </div>
        <div style="margin-bottom:20px;">
            <label style="display:block;color:#BCC2D7;margin-bottom:8px;font-size:14px;font-weight:600;">选项描述：</label>
            <textarea id="editOptionDesc" 
                      style="width:100%;min-height:100px;background:rgba(0,0,0,0.5);border:1px solid rgba(136,149,177,0.5);border-radius:6px;padding:12px;color:#EFF1FE;font-size:14px;resize:vertical;box-sizing:border-box;font-family:inherit;"
                      placeholder="请输入选项描述">${option.desc.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</textarea>
        </div>
        <div style="display:flex;gap:10px;justify-content:flex-end;">
            <button id="editCancel" style="padding:10px 20px;background:rgba(136,149,177,0.3);border:1px solid #8895B1;border-radius:6px;color:#EFF1FE;cursor:pointer;font-size:14px;font-weight:600;transition:all 0.3s;">取消</button>
            <button id="editConfirm" style="padding:10px 20px;background:linear-gradient(135deg,#4ECDC4,#44A08D);border:none;border-radius:6px;color:#fff;cursor:pointer;font-size:14px;font-weight:600;transition:all 0.3s;">确认</button>
        </div>
    `;

    modal.appendChild(dialog);
    document.body.appendChild(modal);

    // 自动聚焦到名称输入框
    setTimeout(() => document.getElementById('editOptionName').focus(), 100);

    // 取消按钮
    document.getElementById('editCancel').onclick = () => {
        document.body.removeChild(modal);
    };

    // 确认按钮
    document.getElementById('editConfirm').onclick = () => {
        const newName = document.getElementById('editOptionName').value.trim();
        const newDesc = document.getElementById('editOptionDesc').value.trim();

        if (!newName) {
            alert('选项名称不能为空！');
            return;
        }

        if (!newDesc) {
            alert('选项描述不能为空！');
            return;
        }

        // 保存旧名称用于更新选择状态
        const oldName = option.name;

        // 更新选项
        option.name = newName;
        option.desc = newDesc;

        // 如果该选项已被选中，也要更新选择状态中的名称和描述
        if (section.isMultiSelect) {
            const selections = APP_STATE.selections[section.key];
            if (Array.isArray(selections)) {
                const selectedOpt = selections.find(s => s.name === oldName);
                if (selectedOpt) {
                    selectedOpt.name = newName;
                    selectedOpt.desc = newDesc;
                }
            }
        } else {
            if (APP_STATE.selections[section.key]?.name === oldName) {
                APP_STATE.selections[section.key].name = newName;
                APP_STATE.selections[section.key].desc = newDesc;
            }
        }

        // 关闭对话框
        document.body.removeChild(modal);

        // 重新渲染
        renderCurrentPage();
        console.log(`✅ 已编辑自定义选项: ${oldName} -> ${newName}`);
    };

    // 点击背景关闭
    modal.onclick = (e) => {
        if (e.target === modal) {
            document.body.removeChild(modal);
        }
    };

    // ESC键关闭
    const escHandler = (e) => {
        if (e.key === 'Escape') {
            if (document.body.contains(modal)) {
                document.body.removeChild(modal);
            }
            document.removeEventListener('keydown', escHandler);
        }
    };
    document.addEventListener('keydown', escHandler);
}

function applyCustom(sectionKey) {
    const nameInput = document.getElementById(`custom_${sectionKey}_name`);
    const descInput = document.getElementById(`custom_${sectionKey}_desc`);

    if (!nameInput || !descInput) return;

    const name = nameInput.value.trim();
    const desc = descInput.value.trim();

    if (!name || !desc) {
        alert('请输入完整的名称和描述！');
        return;
    }

    // 查找对应的section并添加自定义选项
    let found = false;
    for (const module of MODULES_DATA) {
        const section = module.sections.find(s => s.key === sectionKey);
        if (section) {
            // 创建自定义选项，标记为可删除
            const customOption = {
                name: name,
                desc: desc,
                cost: 0,
                isCustom: true  // 标记为自定义选项
            };

            // 添加到选项列表
            section.options.push(customOption);
            found = true;
            break;
        }
    }

    if (!found) {
        alert('未找到对应的选项区域！');
        return;
    }

    // 清空输入框
    nameInput.value = '';
    descInput.value = '';

    // 重新渲染当前页面
    renderCurrentPage();
}

function updateRemainingPoints() {
    const used = calculateUsedPoints();
    const remaining = APP_STATE.totalPoints - used;

    $('remainingPoints').textContent = remaining;
    $('totalPoints').textContent = APP_STATE.totalPoints;

    // 更新颜色
    const box = $('remainingPointsBox');
    if (remaining < 0) {
        box.style.background = 'rgba(255,107,107,0.15)';
        box.style.borderColor = '#FF6B6B';
    } else {
        box.style.background = 'rgba(78,205,196,0.15)';
        box.style.borderColor = '#4ECDC4';
    }

    updateOutputPreview();
}

