// 防抖计时器
let renderDebounceTimer = null;

function renderCurrentPage() {
    if (APP_STATE.isRendering) {
        return;
    }

    if (APP_STATE.renderTimer) {
        clearTimeout(APP_STATE.renderTimer);
        APP_STATE.renderTimer = null;
    }

    APP_STATE.isRendering = true;

    requestAnimationFrame(() => {
        try {
            const page = APP_STATE.currentPage;
            let html = '';

            if (page === 0) {
                html = renderPage0();
            } else if (page === 9) {
                html = renderPage8();
            } else if (page >= 1 && page <= 8) {
                const moduleIndex = page - 1;
                if (moduleIndex < MODULES_DATA.length) {
                    html = renderModule(MODULES_DATA[moduleIndex]);
                } else {
                    html = '<div style="padding:40px;text-align:center;color:#8895B1;">此模块数据尚未添加</div>';
                }
            } else {
                html = '<div style="padding:40px;text-align:center;color:#8895B1;">未知页面</div>';
            }

            const container = $('mainContentArea');
            if (container) {
                container.innerHTML = html;
            }

            renderNavButtons();

        } catch (error) {
            console.error('渲染页面时出错:', error);
        } finally {
            APP_STATE.isRendering = false;
        }
    });
}

function renderModule(module) {
    return `
        <div class="section-title">
            <span>${module.title}</span>
            <button class="random-btn" onclick="randomModule(${MODULES_DATA.indexOf(module)})">🎲 随机</button>
        </div>
        ${module.sections.map(section => `
            <div style="margin-bottom:25px;">
                <div style="font-size:15px;color:#BCC2D7;font-weight:600;margin:15px 0 10px;padding-left:8px;border-left:3px solid #8895B1;">
                    ${section.title}
                </div>
                <div class="option-group">
                    ${section.options.map((opt, optIdx) => {
                        let isSelected;
                        if (section.isMultiSelect) {
                            // 多选：检查是否在数组中
                            const selections = APP_STATE.selections[section.key];
                            isSelected = Array.isArray(selections) && selections.some(s => s.name === opt.name);
                        } else {
                            // 单选：检查name是否匹配
                            isSelected = APP_STATE.selections[section.key]?.name === opt.name;
                        }
                        const moduleIdx = MODULES_DATA.indexOf(module);
                        const sectionIdx = module.sections.indexOf(section);
                        // 所有选项都显示方框标识（单选和多选）
                        const selectIcon = isSelected ? '☑' : '☐';
                        const editBtn = opt.isCustom ? `<button class="edit-custom-btn" onclick="event.stopPropagation();editCustomOption(${moduleIdx}, ${sectionIdx}, ${optIdx})" title="编辑自定义选项">✎</button>` : '';
                        const deleteBtn = opt.isCustom ? `<button class="delete-custom-btn" onclick="event.stopPropagation();deleteCustomOption(${moduleIdx}, ${sectionIdx}, ${optIdx})" title="删除自定义选项">×</button>` : '';
                        return `
                        <div class="option-item ${isSelected ? 'selected' : ''}" 
                             id="option-${moduleIdx}-${sectionIdx}-${optIdx}"
                             onclick="selectOptionByIndex(${moduleIdx}, ${sectionIdx}, ${optIdx})">
                            <div style="display:flex;align-items:center;justify-content:space-between;width:100%;">
                                <div style="flex:1;">
                                    <span style="margin-right:5px;font-size:16px;">${selectIcon}</span>
                                    <span class="option-name">${opt.name}</span>
                                    ${opt.cost > 0 ? `<span class="option-cost">${opt.cost}点</span>` : ''}
                                    ${opt.isCustom ? `<span style="margin-left:5px;font-size:11px;color:#FFD93D;background:rgba(255,217,61,0.2);padding:2px 6px;border-radius:3px;">自定义</span>` : ''}
                                </div>
                                <div style="display:flex;gap:4px;">
                                    ${editBtn}
                                    ${deleteBtn}
                                </div>
                            </div>
                            <div class="option-desc">${opt.desc}</div>
                        </div>
                        `;
                    }).join('')}
                </div>
                <div class="custom-input">
                    <div class="custom-input-row">
                        <input type="text" id="custom_${section.key}_name" placeholder="输入自定义${section.title}名称" style="flex:1">
                    </div>
                    <div class="custom-input-row" style="margin-top:5px">
                        <input type="text" id="custom_${section.key}_desc" placeholder="输入${section.title}详情描述" style="flex:1">
                    </div>
                    <div class="custom-input-row" style="margin-top:5px">
                        <button class="apply-btn" onclick="applyCustom('${section.key}')">应用</button>
                    </div>
                </div>
            </div>
        `).join('')}
    `;
}

function renderNavButtons() {
    const html = APP_STATE.navs.map((nav, idx) => `
        <button class="nav-btn ${APP_STATE.currentPage === idx ? 'active' : ''}" 
                onclick="switchPage(${idx})">
            ${nav}
        </button>
    `).join('');
    $('navButtons').innerHTML = html;
}

// ==================== 交互函数 ====================
function switchPage(pageIndex) {
    if (APP_STATE.currentPage === pageIndex) {
        return;
    }

    if (APP_STATE.isRendering) {
        return;
    }

    APP_STATE.currentPage = pageIndex;
    renderCurrentPage();
}

function applyCustomPoints() {
    const input = document.getElementById('customPointsInput');
    if (!input) return;

    const customPoints = parseInt(input.value);
    if (isNaN(customPoints) || customPoints <= 0) {
        alert('请输入有效的点数（大于0）！');
        return;
    }

    setTotalPoints(customPoints);
    input.value = '';
}

function setTotalPoints(points) {
    APP_STATE.totalPoints = points;
    renderCurrentPage();
    updateRemainingPoints();
}

function updateAttrDisplay(attrName, value) {
    let newVal = parseInt(value) || 0;
    newVal = Math.max(-100, Math.min(1000, newVal));
    APP_STATE.attrs[attrName] = newVal;

    const attrSelectors = document.querySelectorAll('.attr-selector');
    for (let i = 0; i < attrSelectors.length; i++) {
        const selector = attrSelectors[i];
        const nameEl = selector.querySelector('.attr-name');

        if (nameEl && nameEl.textContent === attrName) {
            const valueEl = selector.querySelector('.attr-value');
            const descEl = selector.querySelector('.attr-desc');
            const inputEl = selector.querySelector('.attr-input');
            const sliderEl = selector.querySelector('.attr-slider');

            if (valueEl) valueEl.textContent = newVal;
            if (descEl) descEl.textContent = getAttrDesc(attrName, newVal);
            if (inputEl && document.activeElement !== inputEl) inputEl.value = newVal;
            if (sliderEl && document.activeElement !== sliderEl) sliderEl.value = newVal;
            break;
        }
    }

    updateRemainingPoints();
}

function adjustAttr(attrName, delta) {
    const currentVal = APP_STATE.attrs[attrName] || 0;
    let newVal = currentVal + delta;
    newVal = Math.max(-100, Math.min(1000, newVal));
    APP_STATE.attrs[attrName] = newVal;
    renderCurrentPage();
    updateRemainingPoints();
}

function setAttr(attrName, value) {
    let newVal = parseInt(value) || 0;
    // 所有属性范围是-100到1000
    newVal = Math.max(-100, Math.min(1000, newVal));
    APP_STATE.attrs[attrName] = newVal;
    // 仅更新点数和输出，不重新渲染整个页面
    updateRemainingPoints();
}

