}

// ==================== 旧存档格式处理 ====================

// 处理旧存档格式的兼容性函数
// 属性键名列表，用于旧存档格式兼容性处理
const ATTR_KEYS = ['物攻', '法攻', '物防', '法防', '悟性', '气性', '气运', '魅力'];

// 处理旧存档格式兼容
function processOldArchiveFormat(data) {
    try {
        console.log('开始处理旧存档格式兼容性...');

        // 处理旧版本的属性格式
        if (data.attrs) {
            // 格式1: 简单对象 {'物攻': 10}
            if (typeof data.attrs === 'object' && !Array.isArray(data.attrs)) {
                const processedAttrs = {};

                // 遍历属性，处理各种可能的格式
                for (const [key, value] of Object.entries(data.attrs)) {
                    // 跳过非标准属性
                    if (!ATTR_KEYS.includes(key)) {
                        console.warn(`跳过未知属性: ${key}`);
                        continue;
                    }

                    let attrValue = 0;

                    // 处理不同的值格式
                    if (typeof value === 'number') {
                        attrValue = value;
                    } else if (typeof value === 'string') {
                        attrValue = parseInt(value, 10) || 0;
                    } else if (typeof value === 'object' && value !== null) {
                        // 格式2: 嵌套对象 {'物攻': {value: 10}} 或 {'物攻': {base: 10}}
                        attrValue = value.value || value.base || 0;
                    }

                    // 应用范围限制 - 所有属性范围都是-100到1000
                    processedAttrs[key] = Math.max(-100, Math.min(1000, attrValue));
                }

                data.attrs = processedAttrs;
            }
            // 格式3: 数组格式 [{'name': '物攻', 'value': 10}]
            else if (Array.isArray(data.attrs)) {
                const processedAttrs = {};

                data.attrs.forEach(item => {
                    if (item && typeof item === 'object' && item.name) {
                        const key = item.name;

                        // 跳过非标准属性
                        if (!ATTR_KEYS.includes(key)) {
                            console.warn(`跳过未知属性: ${key}`);
                            return;
                        }

                        let attrValue = 0;

                        // 处理不同的值格式
                        if (typeof item.value === 'number') {
                            attrValue = item.value;
                        } else if (typeof item.value === 'string') {
                            attrValue = parseInt(item.value, 10) || 0;
                        } else if (typeof item.base === 'number') {
                            attrValue = item.base;
                        }

                        // 应用范围限制 - 所有属性范围都是-100到1000
                        processedAttrs[key] = Math.max(-100, Math.min(1000, attrValue));
                    }
                });

                data.attrs = processedAttrs;
            }
        }

        // 处理旧版本的选择格式
        if (data.selections) {
            const processedSelections = {};

            // 遍历所有选择
            for (const [key, value] of Object.entries(data.selections)) {
                // 单选项处理
                if (value && typeof value === 'object' && !Array.isArray(value)) {
                    // 确保有name属性
                    if (!value.name) {
                        console.warn(`单选项${key}缺少name属性，跳过`);
                        continue;
                    }

                    // 确保有desc属性
                    if (!value.desc) {
                        value.desc = '无描述';
                    }

                    // 确保有cost属性
                    if (typeof value.cost !== 'number') {
                        value.cost = 0;
                    }

                    processedSelections[key] = value;
                }
                // 多选项处理
                else if (Array.isArray(value)) {
                    // 过滤无效选项
                    const validItems = value.filter(item => {
                        if (!item || typeof item !== 'object') return false;
                        if (!item.name) return false;
                        if (typeof item.cost !== 'number') item.cost = 0;
                        if (!item.desc) item.desc = '无描述';
                        return true;
                    });

                    if (validItems.length > 0) {
                        processedSelections[key] = validItems;
                    }
                }
            }

            data.selections = processedSelections;
        }

        console.log('旧存档格式处理完成');
        return data;
    } catch (error) {
        console.error('处理旧存档格式时出错:', error);
        throw new Error('旧存档格式处理失败: ' + error.message);
    }
}

