function saveArchive() {
    const nameInput = document.getElementById('newArchiveName');
    if (!nameInput) return;

    const name = nameInput.value.trim();
    if (!name) {
        alert('请输入存档名称！');
        return;
    }

    // 收集所有自定义选项
    const customOptions = [];
    MODULES_DATA.forEach((module, moduleIdx) => {
        module.sections.forEach((section, sectionIdx) => {
            section.options.forEach((opt, optIdx) => {
                if (opt.isCustom) {
                    customOptions.push({
                        moduleIdx: moduleIdx,
                        sectionIdx: sectionIdx,
                        sectionKey: section.key,
                        option: JSON.parse(JSON.stringify(opt))
                    });
                }
            });
        });
    });

    const archiveData = {
        name: name,
        date: new Date().toLocaleString('zh-CN'),
        data: {
            totalPoints: APP_STATE.totalPoints,
            attrs: JSON.parse(JSON.stringify(APP_STATE.attrs)),
            selections: JSON.parse(JSON.stringify(APP_STATE.selections)),
            customOptions: customOptions // 保存自定义选项
        }
    };

    const archives = JSON.parse(localStorage.getItem('wanyu-archives') || '[]');
    archives.push(archiveData);
    localStorage.setItem('wanyu-archives', JSON.stringify(archives));

    nameInput.value = '';
    alert('✅ 存档保存成功！');
    renderCurrentPage(); // 刷新页面显示新存档
}

function loadArchive(index) {
    const archives = JSON.parse(localStorage.getItem('wanyu-archives') || '[]');

    if (index < 0 || index >= archives.length) {
        alert('存档不存在！');
        return;
    }

    if (!confirm('载入存档将覆盖当前选择，确定要载入吗？')) {
        return;
    }

    try {
        const archive = archives[index];
        console.log('开始载入存档:', archive.name);

        const data = JSON.parse(JSON.stringify(archive.data));
        const processedData = processOldArchiveFormat(data);

        if (typeof processedData.totalPoints === 'number' && processedData.totalPoints > 0) {
            APP_STATE.totalPoints = processedData.totalPoints;
        }

        if (processedData.attrs && typeof processedData.attrs === 'object') {
            APP_STATE.attrs = JSON.parse(JSON.stringify(processedData.attrs));
        }

        MODULES_DATA.forEach(function(module) {
            module.sections.forEach(function(section) {
                section.options = section.options.filter(function(opt) { return !opt.isCustom; });
            });
        });

        const addedCustomOptions = {};

        if (processedData.customOptions && Array.isArray(processedData.customOptions)) {
            processedData.customOptions.forEach(function(customOpt) {
                if (customOpt.moduleIdx !== undefined && 
                    customOpt.sectionIdx !== undefined && 
                    customOpt.sectionKey && 
                    customOpt.option) {

                    const optKey = customOpt.sectionKey + '_' + customOpt.option.name;

                    if (addedCustomOptions[optKey]) {
                        return;
                    }

                    try {
                        const module = MODULES_DATA[customOpt.moduleIdx];
                        if (module && module.sections[customOpt.sectionIdx]) {
                            const section = module.sections[customOpt.sectionIdx];
                            if (section.key === customOpt.sectionKey) {
                                const exists = section.options.some(function(opt) { return opt.name === customOpt.option.name; });
                                if (!exists) {
                                    section.options.push(customOpt.option);
                                    addedCustomOptions[optKey] = true;
                                }
                            }
                        }
                    } catch (error) {
                        console.error('恢复自定义选项失败:', error);
                    }
                }
            });
        }

        if (processedData.selections && typeof processedData.selections === 'object') {
            APP_STATE.selections = JSON.parse(JSON.stringify(processedData.selections));

            for (const key in APP_STATE.selections) {
                const selection = APP_STATE.selections[key];

                for (let m = 0; m < MODULES_DATA.length; m++) {
                    const module = MODULES_DATA[m];
                    for (let s = 0; s < module.sections.length; s++) {
                        const section = module.sections[s];
                        if (section.key === key) {
                            if (selection && typeof selection === 'object' && !Array.isArray(selection)) {
                                const optKey = key + '_' + selection.name;
                                if (!addedCustomOptions[optKey]) {
                                    const exists = section.options.some(function(opt) { return opt.name === selection.name; });
                                    if (!exists && selection.name) {
                                        const customOpt = {
                                            name: selection.name,
                                            desc: selection.desc || '无描述',
                                            cost: selection.cost || 0,
                                            isCustom: true
                                        };
                                        section.options.push(customOpt);
                                        addedCustomOptions[optKey] = true;
                                    }
                                }
                            } else if (Array.isArray(selection)) {
                                selection.forEach(function(item) {
                                    if (item && item.name) {
                                        const optKey = key + '_' + item.name;
                                        if (!addedCustomOptions[optKey]) {
                                            const exists = section.options.some(function(opt) { return opt.name === item.name; });
                                            if (!exists) {
                                                const customOpt = {
                                                    name: item.name,
                                                    desc: item.desc || '无描述',
                                                    cost: item.cost || 0,
                                                    isCustom: true
                                                };
                                                section.options.push(customOpt);
                                                addedCustomOptions[optKey] = true;
                                            }
                                        }
                                    }
                                });
                            }
                            break;
                        }
                    }
                }
            }
        }

        alert('存档载入成功！');
        APP_STATE.currentPage = 0;
        renderCurrentPage();
        updateRemainingPoints();
    } catch (e) {
        console.error('载入存档时发生错误:', e);
        alert('载入存档失败：' + e.message);
    }
}

