// 收集当前所有选项数据
function collectCurrentData() {
    var customOptions = [];

    for (var moduleIdx = 0; moduleIdx < MODULES_DATA.length; moduleIdx++) {
        var module = MODULES_DATA[moduleIdx];
        for (var sectionIdx = 0; sectionIdx < module.sections.length; sectionIdx++) {
            var section = module.sections[sectionIdx];
            for (var optIdx = 0; optIdx < section.options.length; optIdx++) {
                var opt = section.options[optIdx];
                if (opt.isCustom) {
                    customOptions.push({
                        moduleIdx: moduleIdx,
                        sectionIdx: sectionIdx,
                        sectionKey: section.key,
                        option: {
                            name: opt.name,
                            desc: opt.desc,
                            cost: opt.cost || 0,
                            isCustom: true
                        }
                    });
                }
            }
        }
    }

    return {
        totalPoints: APP_STATE.totalPoints,
        attrs: JSON.parse(JSON.stringify(APP_STATE.attrs)),
        selections: JSON.parse(JSON.stringify(APP_STATE.selections)),
        customOptions: customOptions
    };
}

// 通用JSON文件下载函数
function downloadJSON(data, filename) {
    try {
        var jsonStr = JSON.stringify(data, null, 2);
        var blob = new Blob([jsonStr], { type: 'application/json;charset=utf-8' });
        var url = URL.createObjectURL(blob);

        var a = document.createElement('a');
        a.href = url;
        a.download = filename;
        a.style.display = 'none';
        document.body.appendChild(a);
        a.click();

        setTimeout(function() {
            if (document.body.contains(a)) {
                document.body.removeChild(a);
            }
            URL.revokeObjectURL(url);
        }, 100);

        return true;
    } catch (e) {
        console.error('文件下载失败:', e);
        // 备用方案：复制到剪贴板
        try {
            var jsonStr2 = JSON.stringify(data, null, 2);
            var textArea = document.createElement('textarea');
            textArea.value = jsonStr2;
            textArea.style.position = 'fixed';
            textArea.style.left = '-9999px';
            textArea.style.top = '0';
            document.body.appendChild(textArea);
            textArea.focus();
            textArea.select();

            var successful = document.execCommand('copy');
            document.body.removeChild(textArea);

            if (successful) {
                alert('文件下载不支持，JSON内容已复制到剪贴板，请手动保存为.json文件');
                return true;
            }
        } catch (e2) {
            console.error('复制到剪贴板也失败:', e2);
        }
        alert('导出失败：' + e.message);
        return false;
    }
}

