// 导出指定存档为JSON
function exportArchiveAsJSON(index) {
    var archives = JSON.parse(localStorage.getItem('wanyu-archives') || '[]');

    if (index < 0 || index >= archives.length) {
        alert('存档不存在！');
        return;
    }

    var archive = archives[index];
    var exportData = {
        version: '1.0',
        type: 'archive',
        name: archive.name,
        date: archive.date,
        isPreset: archive.isPreset || false,
        exportTime: new Date().toLocaleString('zh-CN'),
        data: archive.data
    };

    var safeName = archive.name.replace(/[<>:"/\\|?*\s]/g, '_').substring(0, 30);
    var timestamp = new Date().getTime();
    var filename = 'wanyu_archive_' + safeName + '_' + timestamp + '.json';

    if (downloadJSON(exportData, filename)) {
        console.log('存档导出成功:', archive.name);
    }
}

// 从JSON数据导入（核心函数）
function importFromJSON(jsonData) {
    try {
        console.log('开始导入JSON数据...');

        // 验证基本结构
        if (!jsonData || typeof jsonData !== 'object') {
            return { success: false, message: '无效的JSON数据：不是一个对象' };
        }

        // 获取data字段
        var data = null;
        if (jsonData.data && typeof jsonData.data === 'object') {
            // 标准格式：有version和data字段
            data = jsonData.data;
            console.log('检测到标准JSON格式，版本:', jsonData.version || '未知');
        } else if (jsonData.totalPoints !== undefined || jsonData.attrs || jsonData.selections) {
            // 兼容格式：直接是data内容
            data = jsonData;
            console.log('检测到简化JSON格式');
        } else {
            return { success: false, message: 'JSON格式不正确：缺少data字段或必要属性' };
        }

        // 1. 恢复总点数
        if (typeof data.totalPoints === 'number' && data.totalPoints > 0) {
            APP_STATE.totalPoints = data.totalPoints;
            console.log('恢复总点数:', APP_STATE.totalPoints);
        } else {
            console.log('未找到有效的总点数，保持默认值');
        }

        // 2. 恢复属性
        if (data.attrs && typeof data.attrs === 'object') {
            var attrKeys = ['物攻', '法攻', '物防', '法防', '悟性', '气性', '气运', '魅力'];
            for (var i = 0; i < attrKeys.length; i++) {
                var key = attrKeys[i];
                if (typeof data.attrs[key] === 'number') {
                    var value = data.attrs[key];
                    APP_STATE.attrs[key] = Math.max(-100, Math.min(1000, value));
                }
            }
            console.log('恢复属性完成:', APP_STATE.attrs);
        } else {
            console.log('未找到属性数据');
        }

        // 3. 清除现有自定义选项
        for (var m = 0; m < MODULES_DATA.length; m++) {
            var module = MODULES_DATA[m];
            for (var s = 0; s < module.sections.length; s++) {
                var section = module.sections[s];
                var newOptions = [];
                for (var o = 0; o < section.options.length; o++) {
                    if (!section.options[o].isCustom) {
                        newOptions.push(section.options[o]);
                    }
                }
                section.options = newOptions;
            }
        }
        console.log('已清除现有自定义选项');

        // 4. 恢复自定义选项
        var addedCustomOptions = {};
        if (data.customOptions && Array.isArray(data.customOptions)) {
            for (var c = 0; c < data.customOptions.length; c++) {
                var customOpt = data.customOptions[c];

                if (customOpt.moduleIdx === undefined || 
                    customOpt.sectionIdx === undefined || 
                    !customOpt.sectionKey || 
                    !customOpt.option) {
                    console.log('跳过无效的自定义选项:', c);
                    continue;
                }

                var optKey = customOpt.sectionKey + '_' + customOpt.option.name;
                if (addedCustomOptions[optKey]) {
                    console.log('跳过重复的自定义选项:', optKey);
                    continue;
                }

                var targetModule = MODULES_DATA[customOpt.moduleIdx];
                if (!targetModule) {
                    console.log('模块索引无效:', customOpt.moduleIdx);
                    continue;
                }

                var targetSection = targetModule.sections[customOpt.sectionIdx];
                if (!targetSection) {
                    console.log('分区索引无效:', customOpt.sectionIdx);
                    continue;
                }

                if (targetSection.key !== customOpt.sectionKey) {
                    console.log('分区key不匹配:', targetSection.key, '!=', customOpt.sectionKey);
                    continue;
                }

                // 检查是否已存在同名选项
                var existsInOptions = false;
                for (var eo = 0; eo < targetSection.options.length; eo++) {
                    if (targetSection.options[eo].name === customOpt.option.name) {
                        existsInOptions = true;
                        break;
                    }
                }

                if (!existsInOptions) {
                    targetSection.options.push({
                        name: customOpt.option.name,
                        desc: customOpt.option.desc || '无描述',
                        cost: customOpt.option.cost || 0,
                        isCustom: true
                    });
                    addedCustomOptions[optKey] = true;
                    console.log('恢复自定义选项:', optKey);
                }
            }
        }

        // 5. 恢复选择
        if (data.selections && typeof data.selections === 'object') {
            APP_STATE.selections = {};

            for (var selKey in data.selections) {
                if (!data.selections.hasOwnProperty(selKey)) continue;

                var selection = data.selections[selKey];

                // 查找对应的section
                var foundSection = null;
                var foundModule = null;
                for (var fm = 0; fm < MODULES_DATA.length; fm++) {
                    var mod = MODULES_DATA[fm];
                    for (var fs = 0; fs < mod.sections.length; fs++) {
                        if (mod.sections[fs].key === selKey) {
                            foundSection = mod.sections[fs];
                            foundModule = mod;
                            break;
                        }
                    }
                    if (foundSection) break;
                }

                if (!foundSection) {
                    console.log('未找到对应的分区:', selKey);
                    continue;
                }

                // 处理单选
                if (selection && typeof selection === 'object' && !Array.isArray(selection)) {
                    if (!selection.name) {
                        console.log('单选项缺少name:', selKey);
                        continue;
                    }

                    // 检查选项是否存在，不存在则创建
                    var existsOpt = false;
                    for (var eo2 = 0; eo2 < foundSection.options.length; eo2++) {
                        if (foundSection.options[eo2].name === selection.name) {
                            existsOpt = true;
                            break;
                        }
                    }

                    if (!existsOpt) {
                        var newOptKey = selKey + '_' + selection.name;
                        if (!addedCustomOptions[newOptKey]) {
                            foundSection.options.push({
                                name: selection.name,
                                desc: selection.desc || '无描述',
                                cost: selection.cost || 0,
                                isCustom: true
                            });
                            addedCustomOptions[newOptKey] = true;
                            console.log('自动创建缺失的单选选项:', newOptKey);
                        }
                    }

                    APP_STATE.selections[selKey] = {
                        name: selection.name,
                        desc: selection.desc || '无描述',
                        cost: selection.cost || 0
                    };
                    if (selection.isCustom) {
                        APP_STATE.selections[selKey].isCustom = true;
                    }
                }
                // 处理多选
                else if (Array.isArray(selection)) {
                    var validItems = [];

                    for (var si = 0; si < selection.length; si++) {
                        var item = selection[si];
                        if (!item || !item.name) {
                            continue;
                        }

                        // 检查选项是否存在，不存在则创建
                        var existsItem = false;
                        for (var ei = 0; ei < foundSection.options.length; ei++) {
                            if (foundSection.options[ei].name === item.name) {
                                existsItem = true;
                                break;
                            }
                        }

                        if (!existsItem) {
                            var newItemKey = selKey + '_' + item.name;
                            if (!addedCustomOptions[newItemKey]) {
                                foundSection.options.push({
                                    name: item.name,
                                    desc: item.desc || '无描述',
                                    cost: item.cost || 0,
                                    isCustom: true
                                });
                                addedCustomOptions[newItemKey] = true;
                                console.log('自动创建缺失的多选选项:', newItemKey);
                            }
                        }

                        var validItem = {
                            name: item.name,
                            desc: item.desc || '无描述',
                            cost: item.cost || 0
                        };
                        if (item.isCustom) {
                            validItem.isCustom = true;
                        }
                        validItems.push(validItem);
                    }

                    if (validItems.length > 0) {
                        APP_STATE.selections[selKey] = validItems;
                    }
                }
            }

            console.log('恢复选择完成:', APP_STATE.selections);
        } else {
            APP_STATE.selections = {};
            console.log('未找到选择数据，已清空');
        }

        return { success: true, message: 'JSON导入成功' };

    } catch (e) {
        console.error('导入JSON时发生错误:', e);
        return { success: false, message: '导入失败：' + e.message };
    }
}

// 处理拖拽悬停
function handleDragOver(event) {
    event.preventDefault();
    event.stopPropagation();
    var dropZone = document.getElementById('jsonDropZone');
    if (dropZone) {
        dropZone.style.borderColor = '#4ECDC4';
        dropZone.style.background = 'rgba(78,205,196,0.2)';
    }
}

// 处理拖拽离开
function handleDragLeave(event) {
    event.preventDefault();
    event.stopPropagation();
    var dropZone = document.getElementById('jsonDropZone');
    if (dropZone) {
        dropZone.style.borderColor = 'rgba(78,205,196,0.3)';
        dropZone.style.background = 'rgba(78,205,196,0.05)';
    }
}

// 处理文件拖放
function handleFileDrop(event) {
    event.preventDefault();
    event.stopPropagation();

    var dropZone = document.getElementById('jsonDropZone');
    if (dropZone) {
        dropZone.style.borderColor = 'rgba(78,205,196,0.3)';
        dropZone.style.background = 'rgba(78,205,196,0.05)';
    }

    var files = event.dataTransfer.files;
    if (!files || files.length === 0) {
        alert('未检测到文件');
        return;
    }

    var file = files[0];
    var fileName = file.name.toLowerCase();

    if (!fileName.endsWith('.json')) {
        alert('请拖入JSON格式的文件（.json）');
        return;
    }

    var reader = new FileReader();

    reader.onload = function(e) {
        try {
            var content = e.target.result;
            var textarea = document.getElementById('importTextArea');
            if (textarea) {
                textarea.value = content;
            }

            // 尝试解析并导入
            var jsonData = JSON.parse(content);
            var result = importFromJSON(jsonData);

            if (result.success) {
                APP_STATE.currentPage = 0;
                renderCurrentPage();
                updateRemainingPoints();

                if (textarea) {
                    textarea.value = '';
                }

                alert('JSON文件导入成功！已恢复所有设置。');
            } else {
                alert('JSON导入失败：' + result.message);
            }
        } catch (parseError) {
            alert('JSON解析失败：' + parseError.message);
        }
    };

    reader.onerror = function() {
        alert('文件读取失败，请重试');
    };

    reader.readAsText(file, 'UTF-8');
}
