    <script>
        // 简单的交互动画效果
        document.addEventListener('DOMContentLoaded', function() {
            // 为所有卡片添加鼠标悬停效果
            const cards = document.querySelectorAll('.card');
            cards.forEach(card => {
                card.addEventListener('mouseenter', function() {
                    this.style.transform = 'translateY(-8px)';
                });

                card.addEventListener('mouseleave', function() {
                    this.style.transform = 'translateY(0)';
                });
            });

            // 开始按钮点击效果 - 切换到开局选择器
            const startButtons = document.querySelectorAll('.start-button');
            startButtons.forEach(function(button) {
                button.addEventListener('click', function(e) {
                    e.preventDefault();
                    switchToPage('page-intro', 'page-selector');
                });
            });
        });

        // 页面切换函数
        function switchToPage(fromPageId, toPageId) {
            const fromPage = document.getElementById(fromPageId);
            const toPage = document.getElementById(toPageId);

            if (!fromPage || !toPage) return;

            // 隐藏当前页面
            fromPage.classList.remove('active');
            fromPage.classList.add('hidden');

            // 显示目标页面
            toPage.classList.remove('next');
            toPage.classList.add('active');

            // 如果切换到选择器页面，初始化开局选择器
            if (toPageId === 'page-selector') {
                initSelector();
            }

            // 重置页面状态
            setTimeout(function() {
                fromPage.classList.remove('hidden');
                fromPage.classList.add('next');
            }, 600);
        }

        // 初始化开局选择器
        function initSelector() {
            if (typeof initPresetArchive === 'function') initPresetArchive();
            if (typeof renderNavButtons === 'function') renderNavButtons();
            if (typeof renderCurrentPage === 'function') renderCurrentPage();
            if (typeof updateRemainingPoints === 'function') updateRemainingPoints();
        }
    </script>
    <script>
        document.addEventListener('DOMContentLoaded', () => {
            const startButton = document.getElementById('start-journey-button');
            const introPage = document.getElementById('page-intro');
            const dlcPage = document.getElementById('page-dlc');
            const selectorPage = document.getElementById('page-selector');

            if (startButton && introPage && dlcPage && selectorPage) {
                startButton.addEventListener('click', (event) => {
                    event.preventDefault();

                    // 1. 播放离场动画
                    introPage.classList.add('is-exiting');

                    // 2. 动画结束后切换到DLC选择器页面
                    setTimeout(() => {
                        introPage.classList.remove('active', 'is-exiting');
                        introPage.style.display = 'none';

                        dlcPage.style.display = 'block';
                        dlcPage.classList.add('active', 'is-entering');

                        // 初始化DLC选择器
                        if (typeof DLCCtrl !== 'undefined' && DLCCtrl.boot) {
                            DLCCtrl.boot();
                        }
                    }, 600);
                });
            }
        });

        // ==================== 页面切换函数 ====================
        function showPage(pageIndex) {
            const pages = ['page-intro', 'page-dlc', 'page-selector'];
            if (pageIndex < 0 || pageIndex >= pages.length) return;

            const currentPage = document.querySelector('.page.active');
            const targetPage = document.getElementById(pages[pageIndex]);

            if (currentPage && targetPage) {
                currentPage.classList.add('is-exiting');
                setTimeout(() => {
                    currentPage.classList.remove('active', 'is-exiting');
                    currentPage.style.display = 'none';

                    targetPage.style.display = 'block';
                    targetPage.classList.add('active', 'is-entering');
                }, 600);
            }
        }
