        // ==================== DLC 控制器 ====================
        var DLCCtrl = {
            diffIdx: 6,
            npcMap: {},
            dlcMap: {},
            ready: false,

            async boot() {
                if (this.ready) { this.paint(); return; }
                this._applyDefaults();
                await this._syncFromBook();
                this.paint();
                this.ready = true;
            },

            _applyDefaults: function () {
                var self = this;
                self.diffIdx = 6;
                NPC_TABLE.forEach(function (c) {
                    self.npcMap[c.m] = c.md;
                    self.npcMap[c.f] = c.fd;
                });
                DLC_TABLE.forEach(function (g) {
                    g.items.forEach(function (it) {
                        self.dlcMap[it.entry] = it.on;
                    });
                });
            },

            _syncFromBook: async function () {
                var self = this;
                var bn = await WB.getName();
                if (!bn) return;
                var entries = await WB.readAll(bn);
                if (!entries.length) return;
                var stateMap = {};
                entries.forEach(function (e) { stateMap[e.name] = e.enabled; });
                DIFF_TABLE.forEach(function (d, i) {
                    if (stateMap[d.entry] === true) self.diffIdx = i;
                });
                Object.keys(self.npcMap).forEach(function (k) {
                    if (k in stateMap) self.npcMap[k] = !!stateMap[k];
                });
                Object.keys(self.dlcMap).forEach(function (k) {
                    if (k in stateMap) self.dlcMap[k] = !!stateMap[k];
                });
            },

            paint: function () {
                this._renderDiff();
                this._renderNpc();
                this._renderDlcSubWw156651();
                this._renderDlcSubYu();
                this._renderDlcSubAcacai();
                this._renderDlcSubAkimekaze();
                this._renderDlcSubMyrtenaster();
                this._renderStatus();
            },

            _renderDiff: function () {
                var self = this;
                var box = document.getElementById('sheet-difficulty');
                if (!box) return;
                var html = '<div class="diff-list">';
                DIFF_TABLE.forEach(function (d, i) {
                    var stars = '';
                    for (var s = 0; s < 10; s++) stars += s < i + 1 ? '★' : '☆';
                    var cls = i === self.diffIdx ? 'diff-item picked' : 'diff-item';
                    html += '<div class="' + cls + '" onclick="DLCCtrl.pickDiff(' + i + ')">'
                        + '<span class="d-stars">' + stars + '</span>'
                        + '<div class="d-body">'
                        + '<div class="d-name">' + d.title + '</div>'
                        + '<div class="d-note">' + d.tip + '</div>'
                        + '</div></div>';
                });
                html += '</div>';
                box.innerHTML = html;
            },

            _renderNpc: function () {
                var self = this;
                var box = document.getElementById('sheet-npc');
                if (!box) return;
                var html = '<div class="npc-grid">';
                var npcStart = NPC_TABLE.findIndex(c => c.name === '林墨');
                var npcEnd = NPC_TABLE.findIndex(c => c.name === '云逍遥');
                html += '<div class="npc-controls">'
                    + '<button class="npc-btn" onclick="DLCCtrl.setNpcAll(true)">全开</button>'
                    + '<button class="npc-btn" onclick="DLCCtrl.setNpcAll(false)">全关</button>'
                    + '<button class="npc-btn" onclick="DLCCtrl.setNpcGenderAllF()">全女</button>'
                    + '<button class="npc-btn" onclick="DLCCtrl.setNpcGenderAllM()">全男</button>'
                    + '<button class="npc-btn" onclick="DLCCtrl.setNpcGenderRandom()">随机</button>'
                    + '</div>';
                NPC_TABLE.forEach(function (c, idx) {
                    var mOn = self.npcMap[c.m];
                    var fOn = self.npcMap[c.f];
                    var isGendered = idx >= npcStart && idx <= npcEnd && c.m && c.f;
                    html += '<div class="npc-card">'
                        + '<div class="nc-name">' + c.name + '</div>'
                        + '<div class="nc-trait">' + c.trait + '</div>';
                    if (isGendered) {
                        html += '<div class="nc-row"><span class="nc-label">男性版</span>'
                            + '<label class="sw-wrap"><input type="checkbox"' + (mOn ? ' checked' : '')
                            + ' onchange="DLCCtrl.flipNpc(\'' + c.m + '\',this.checked)"><span class="sw-track"></span></label></div>'
                            + '<div class="nc-row"><span class="nc-label">女性版</span>'
                            + '<label class="sw-wrap"><input type="checkbox"' + (fOn ? ' checked' : '')
                            + ' onchange="DLCCtrl.flipNpc(\'' + c.f + '\',this.checked)"><span class="sw-track"></span></label></div>';
                    } else {
                        html += '<div class="nc-row"><span class="nc-label">版本</span>'
                            + '<label class="sw-wrap"><input type="checkbox"' + (mOn ? ' checked' : '')
                            + ' onchange="DLCCtrl.flipNpc(\'' + c.m + '\',this.checked)"><span class="sw-track"></span></label></div>';
                    }
                    html += '</div>';
                });
                html += '</div>';
                box.innerHTML = html;
            },

            _renderDlc: function () {
                var self = this;
                var box = document.getElementById('sheet-dlcContent');
                if (!box) return;
                var html = '';
                DLC_TABLE.forEach(function (g) {
                    html += '<div class="dlc-group"><div class="dg-title">' + g.group + '</div>';
                    html += '<div class="dg-controls">'
                        + '<button class="dlc-btn" onclick="DLCCtrl.setGroupAll(\'' + g.group + '\', true)">全开</button>'
                        + '<button class="dlc-btn" onclick="DLCCtrl.setGroupAll(\'' + g.group + '\', false)">全关</button>'
                        + '</div>';
                    g.items.forEach(function (it) {
                        var on = self.dlcMap[it.entry];
                        var lampCls = it.lamp === 'b' ? 'lamp-b' : 'lamp-g';
                        html += '<div class="dlc-row"><div class="dr-info">'
                            + '<div class="dr-name"><span class="lamp ' + lampCls + '"></span>' + it.label + '</div>'
                            + '<div class="dr-meta">作者：' + it.author + '</div>'
                            + (it.hint ? '<div class="dr-hint">' + it.hint + '</div>' : '')
                            + '</div><label class="sw-wrap"><input type="checkbox"' + (on ? ' checked' : '')
                            + ' onchange="DLCCtrl.flipDlc(\'' + it.entry + '\',this.checked)">'
                            + '<span class="sw-track"></span></label></div>';
                    });
                    html += '</div>';
                });
                box.innerHTML = html;
            },

            _renderStatus: function () {
                var di = DIFF_TABLE[this.diffIdx];
                document.getElementById('svDiff').textContent = di.tag + '·' + di.title;

                var npcOn = 0, npcAll = 0;
                for (var k in this.npcMap) {
                    npcAll++;
                    if (this.npcMap[k]) npcOn++;
                }
                document.getElementById('svNpc').textContent = npcOn + '/' + npcAll;

                var dlcOn = 0, dlcAll = 0;
                for (var d in this.dlcMap) {
                    dlcAll++;
                    if (this.dlcMap[d]) dlcOn++;
                }
