                    pairs.push({ name: d.entry, enabled: i === self.diffIdx });
                });
                Object.keys(self.npcMap).forEach(function (k) {
                    pairs.push({ name: k, enabled: self.npcMap[k] });
                });
                Object.keys(self.dlcMap).forEach(function (k) {
                    pairs.push({ name: k, enabled: self.dlcMap[k] });
                });
