                var snapshot = {
                    diff: this.diffIdx,
                    npc: Object.assign({}, this.npcMap),
                    dlc: Object.assign({}, this.dlcMap)
                };
                localStorage.setItem('dlcSnapshot', JSON.stringify(snapshot));
