            importLocal: function () {
                try {
                    var raw = localStorage.getItem('dlcSnapshot');
                    if (!raw) { alert('未找到本地存档'); return; }
                    var data = JSON.parse(raw);
                    if (typeof data.diff === 'number' && data.diff >= 0 && data.diff < DIFF_TABLE.length) {
                        this.diffIdx = data.diff;
                    }
                    if (data.npc) {
                        for (var k in data.npc) {
                            if (k in this.npcMap) this.npcMap[k] = !!data.npc[k];
                        }
                    }
                    if (data.dlc) {
                        for (var d in data.dlc) {
                            if (d in this.dlcMap) this.dlcMap[d] = !!data.dlc[d];
                        }
                    }
                    this.paint();
                    alert('设置已加载');
                } catch (e) {
                    alert('加载失败：数据格式异常');
                }
            },

            resetAll: function () {
                this._applyDefaults();
                this.paint();
            },

            goNext: async function () {
                await this._commitToBook();
                APP_STATE.dlcSelections = Object.assign({}, this.dlcMap);
                showPage(2);
            }
