            font-weight: 600;
            color: #4ECDC4;
            margin-bottom: 10px;
        }

        .intro-desc-content {
            font-size: 0.8rem;
            color: #BCC2D7;
            line-height: 1.5;
            margin-bottom: 8px;
        }

        .intro-desc-note {
            font-size: 0.75rem;
            color: #8895B1;
            line-height: 1.5;
            font-style: italic;
        }

        /* ==================== 新增: 游戏风格按钮 ==================== */
        .game-button {
            position: relative;
            width: 100%;
            padding: 12px 20px;
            border: 1px solid rgba(78, 205, 196, 0.4);
            background: linear-gradient(to right, rgba(10, 30, 40, 0.5), rgba(20, 40, 50, 0.8));
            color: #EFF1FE;
            text-decoration: none;
            text-align: center;
            font-weight: 600;
            letter-spacing: 1px;
            transition: all 0.3s ease;
            clip-path: polygon(0 10px, 10px 0, calc(100% - 10px) 0, 100% 10px, 100% calc(100% - 10px), calc(100% - 10px) 100%, 10px 100%, 0 calc(100% - 10px));
        }

        .game-button .text {
            position: relative;
            z-index: 2;
        }

        /* 主按钮样式 */
        .game-button.primary {
            font-size: 1.2rem;
            color: #FFFFFF;
            background: linear-gradient(to right, rgba(78, 205, 196, 0.2), rgba(42, 157, 143, 0.4));
            box-shadow: 0 0 10px rgba(78, 205, 196, 0.2), inset 0 0 15px rgba(78, 205, 196, 0.1);
        }

        .game-button.primary:hover {
            background: linear-gradient(to right, rgba(78, 205, 196, 0.3), rgba(42, 157, 143, 0.6));
            border-color: #4ECDC4;
            color: #fff;
            transform: translateY(-3px) scale(1.02);
            box-shadow: 0 5px 20px rgba(78, 205, 196, 0.4);
        }

        .game-button.primary::before,
        .game-button.primary::after {
            content: '';
            position: absolute;
            width: 12px;
            height: 12px;
            border-color: #4ECDC4;
            border-style: solid;
            transition: all 0.3s ease;
        }

        .game-button.primary::before {
            top: -2px; left: -2px;
            border-width: 2px 0 0 2px;
        }

        .game-button.primary::after {
            bottom: -2px; right: -2px;
            border-width: 0 2px 2px 0;
        }

        .game-button.primary:hover::before { top: 0; left: 0; }
        .game-button.primary:hover::after { bottom: 0; right: 0; }

        /* 次级按钮样式 */
        .game-button.secondary {
            display: flex;
            justify-content: center;
            align-items: center;
            gap: 10px;
            font-size: 0.9rem;
            padding: 10px 20px;
            color: #BCC2D7;
            border-color: rgba(136, 149, 177, 0.3);
            background: rgba(10, 20, 30, 0.6);
        }

        .game-button.secondary .icon {
            display: inline-block;
            width: 8px;
            height: 8px;
            background-color: #8895B1;
            transform: rotate(45deg);
            transition: all 0.3s ease;
        }

        .game-button.secondary:hover {
            color: #EFF1FE;
            border-color: #8895B1;
            transform: translateY(-2px);
            box-shadow: 0 3px 15px rgba(0, 0, 0, 0.2);
        }

        .game-button.secondary:hover .icon {
            background-color: #4ECDC4;
            transform: rotate(45deg) scale(1.2);
        }

        /* ==================== 新增: 页面转场动画 ==================== */
        @keyframes page-out {
            from { opacity: 1; transform: scale(1); filter: blur(0); }
            to { opacity: 0; transform: scale(0.98); filter: blur(8px); }
        }

        @keyframes page-in {
            from { opacity: 0; transform: scale(1.02); filter: blur(8px); }
            to { opacity: 1; transform: scale(1); filter: blur(0); }
        }

        /* 调整.page相关类以支持新动画 */
        .page {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            display: none; /* 默认隐藏 */
        }

        .page.active {
            display: block;
            position: relative; /* 保持文档流 */
        }

        .page.is-entering {
            display: block;
            animation: page-in 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
        }

        .page.is-exiting {
            display: block;
            animation: page-out 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
        }

        /* ==================== 滚动条样式 ==================== */
        ::-webkit-scrollbar {
            width: 10px;
            height: 10px;
        }

        ::-webkit-scrollbar-track {
            background: rgba(0, 0, 0, 0.2);
            border-radius: 5px;
        }

        ::-webkit-scrollbar-thumb {
            background: rgba(136, 149, 177, 0.5);
            border-radius: 5px;
        }

        ::-webkit-scrollbar-thumb:hover {
            background: rgba(136, 149, 177, 0.7);
        }

