    height: 20px;
    display: inline-block;
}

.sw-wrap input {
    opacity: 0;
    width: 0;
    height: 0;
    position: absolute;
}

.sw-track {
    position: absolute;
    inset: 0;
    background: rgba(80, 80, 80, 0.35);
    border: 1px solid rgba(136, 149, 177, 0.25);
    border-radius: 10px;
    cursor: pointer;
    transition: all 0.25s;
}

.sw-track::after {
    content: '';
    position: absolute;
    width: 14px;
    height: 14px;
    left: 2px;
    bottom: 2px;
    background: #7884a0;
    border-radius: 50%;
    transition: all 0.25s;
}

.sw-wrap input:checked + .sw-track {
    background: rgba(78, 205, 196, 0.25);
    border-color: rgba(78, 205, 196, 0.45);
}

