// 获取属性描述
function getAttrDesc(attrName, value) {
    const levels = ATTR_LEVELS[attrName];
    if (!levels) return '未知属性';
    for (let level of levels) {
        if (value >= level.min && value <= level.max) {
            return level.desc;
        }
    }
    return '超出范围';
}

