// ==================== 工具函数 ====================
function $(id) {
    return document.getElementById(id);
}

function calculateUsedPoints() {
    let used = 0;
    // 计算属性消耗
    for (let key in APP_STATE.attrs) {
        const val = APP_STATE.attrs[key];
        if (key === '气运') {
            used += Math.abs(val - 10) * 2; // 气运每点消耗2点数
        } else {
            used += Math.abs(val - 10);
        }
    }
    // 计算选择消耗（支持单选和多选）
    for (let key in APP_STATE.selections) {
        const selection = APP_STATE.selections[key];
        if (Array.isArray(selection)) {
            // 多选：累加所有选项的cost
            selection.forEach(opt => {
                used += opt.cost || 0;
            });
        } else {
            // 单选：直接加cost
            used += selection.cost || 0;
        }
    }
    return used;
}

function deleteCustomOption(moduleIdx, sectionIdx, optIdx) {
    const module = MODULES_DATA[moduleIdx];
    const section = module.sections[sectionIdx];
    const option = section.options[optIdx];

    if (!option.isCustom) {
        alert('只能删除自定义选项！');
        return;
    }

    if (!confirm(`确定要删除自定义选项"${option.name}"吗？`)) {
        return;
    }

    // 从选项列表中删除
    section.options.splice(optIdx, 1);

    // 如果该选项已被选中，也要清除选择状态
    if (section.isMultiSelect) {
        const selections = APP_STATE.selections[section.key];
        if (Array.isArray(selections)) {
            const idx = selections.findIndex(s => s.name === option.name);
            if (idx >= 0) {
                selections.splice(idx, 1);
                if (selections.length === 0) {
                    delete APP_STATE.selections[section.key];
                }
            }
        }
    } else {
        if (APP_STATE.selections[section.key]?.name === option.name) {
            delete APP_STATE.selections[section.key];
        }
    }

    // 重新渲染
    renderCurrentPage();
    updateRemainingPoints();
}

function editCustomOption(moduleIdx, sectionIdx, optIdx) {
    const module = MODULES_DATA[moduleIdx];
    const section = module.sections[sectionIdx];
    const option = section.options[optIdx];

    if (!option.isCustom) {
        alert('只能编辑自定义选项！');
        return;
    }

    // 创建模态对话框
    const modal = document.createElement('div');
    modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.8);display:flex;align-items:center;justify-content:center;z-index:9999;';

    const dialog = document.createElement('div');
    dialog.style.cssText = 'background:#1a1f2e;border:2px solid #4ECDC4;border-radius:12px;padding:25px;width:600px;max-width:90%;box-shadow:0 8px 32px rgba(0,0,0,0.5);';

    dialog.innerHTML = `
        <div style="font-size:20px;color:#4ECDC4;margin-bottom:20px;font-weight:700;border-bottom:2px solid rgba(78,205,196,0.3);padding-bottom:12px;">✎ 编辑自定义选项</div>
        <div style="margin-bottom:15px;">
            <label style="display:block;color:#BCC2D7;margin-bottom:8px;font-size:14px;font-weight:600;">选项名称：</label>
            <input type="text" id="editOptionName" value="${option.name.replace(/"/g, '&quot;')}" 
                   style="width:100%;background:rgba(0,0,0,0.5);border:1px solid rgba(136,149,177,0.5);border-radius:6px;padding:12px;color:#EFF1FE;font-size:14px;box-sizing:border-box;"
                   placeholder="请输入选项名称">
        </div>
        <div style="margin-bottom:20px;">
            <label style="display:block;color:#BCC2D7;margin-bottom:8px;font-size:14px;font-weight:600;">选项描述：</label>
            <textarea id="editOptionDesc" 
                      style="width:100%;min-height:100px;background:rgba(0,0,0,0.5);border:1px solid rgba(136,149,177,0.5);border-radius:6px;padding:12px;color:#EFF1FE;font-size:14px;resize:vertical;box-sizing:border-box;font-family:inherit;"
                      placeholder="请输入选项描述">${option.desc.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</textarea>
        </div>
        <div style="display:flex;gap:10px;justify-content:flex-end;">
            <button id="editCancel" style="padding:10px 20px;background:rgba(136,149,177,0.3);border:1px solid #8895B1;border-radius:6px;color:#EFF1FE;cursor:pointer;font-size:14px;font-weight:600;transition:all 0.3s;">取消</button>
            <button id="editConfirm" style="padding:10px 20px;background:linear-gradient(135deg,#4ECDC4,#44A08D);border:none;border-radius:6px;color:#fff;cursor:pointer;font-size:14px;font-weight:600;transition:all 0.3s;">确认</button>
        </div>
    `;

    modal.appendChild(dialog);
    document.body.appendChild(modal);

    // 自动聚焦到名称输入框
    setTimeout(() => document.getElementById('editOptionName').focus(), 100);

    // 取消按钮
    document.getElementById('editCancel').onclick = () => {
        document.body.removeChild(modal);
    };

    // 确认按钮
    document.getElementById('editConfirm').onclick = () => {
        const newName = document.getElementById('editOptionName').value.trim();
        const newDesc = document.getElementById('editOptionDesc').value.trim();

        if (!newName) {
            alert('选项名称不能为空！');
            return;
        }

        if (!newDesc) {
            alert('选项描述不能为空！');
            return;
        }

        // 保存旧名称用于更新选择状态
        const oldName = option.name;

        // 更新选项
        option.name = newName;
        option.desc = newDesc;

        // 如果该选项已被选中，也要更新选择状态中的名称和描述
        if (section.isMultiSelect) {
            const selections = APP_STATE.selections[section.key];
            if (Array.isArray(selections)) {
                const selectedOpt = selections.find(s => s.name === oldName);
                if (selectedOpt) {
                    selectedOpt.name = newName;
                    selectedOpt.desc = newDesc;
                }
            }
        } else {
            if (APP_STATE.selections[section.key]?.name === oldName) {
                APP_STATE.selections[section.key].name = newName;
                APP_STATE.selections[section.key].desc = newDesc;
            }
        }

        // 关闭对话框
        document.body.removeChild(modal);

        // 重新渲染
        renderCurrentPage();
        console.log(`✅ 已编辑自定义选项: ${oldName} -> ${newName}`);
    };

    // 点击背景关闭
    modal.onclick = (e) => {
        if (e.target === modal) {
            document.body.removeChild(modal);
        }
    };

    // ESC键关闭
    const escHandler = (e) => {
        if (e.key === 'Escape') {
            if (document.body.contains(modal)) {
                document.body.removeChild(modal);
            }
            document.removeEventListener('keydown', escHandler);
        }
    };
    document.addEventListener('keydown', escHandler);
}

function applyCustom(sectionKey) {
    const nameInput = document.getElementById(`custom_${sectionKey}_name`);
    const descInput = document.getElementById(`custom_${sectionKey}_desc`);

    if (!nameInput || !descInput) return;

    const name = nameInput.value.trim();
    const desc = descInput.value.trim();

    if (!name || !desc) {
        alert('请输入完整的名称和描述！');
        return;
    }

    // 查找对应的section并添加自定义选项
    let found = false;
    for (const module of MODULES_DATA) {
        const section = module.sections.find(s => s.key === sectionKey);
        if (section) {
            // 创建自定义选项，标记为可删除
            const customOption = {
                name: name,
                desc: desc,
                cost: 0,
                isCustom: true  // 标记为自定义选项
            };

            // 添加到选项列表
            section.options.push(customOption);
            found = true;
            break;
        }
    }

    if (!found) {
        alert('未找到对应的选项区域！');
        return;
    }

    // 清空输入框
    nameInput.value = '';
    descInput.value = '';

    // 重新渲染当前页面
    renderCurrentPage();
}

function updateRemainingPoints() {
    const used = calculateUsedPoints();
    const remaining = APP_STATE.totalPoints - used;

    $('remainingPoints').textContent = remaining;
    $('totalPoints').textContent = APP_STATE.totalPoints;

    // 更新颜色
    const box = $('remainingPointsBox');
    if (remaining < 0) {
        box.style.background = 'rgba(255,107,107,0.15)';
        box.style.borderColor = '#FF6B6B';
    } else {
        box.style.background = 'rgba(78,205,196,0.15)';
        box.style.borderColor = '#4ECDC4';
    }

    updateOutputPreview();
}

function updateOutputPreview() {
    if (APP_STATE.previewUpdateTimer) {
        clearTimeout(APP_STATE.previewUpdateTimer);
    }

    APP_STATE.previewUpdateTimer = setTimeout(() => {
        try {
            const get = (key) => APP_STATE.selections[key];
            const getArray = (key) => {
                const val = APP_STATE.selections[key];
                return Array.isArray(val) ? val : (val ? [val] : []);
            };

            const outputParts = [];

            const used = calculateUsedPoints();
            const remaining = APP_STATE.totalPoints - used;
            outputParts.push('<div style="margin-bottom:10px;padding:8px;background:rgba(78,205,196,0.1);border-radius:4px;text-align:left;border:1px solid rgba(78,205,196,0.2);">');
            outputParts.push('<div>总点数：' + APP_STATE.totalPoints + '</div>');
            outputParts.push('<div style="color:' + (remaining < 0 ? '#FF6B6B' : '#4ECDC4') + '">剩余点数：' + remaining + '</div>');
            outputParts.push('</div>');

            if (get('性别') || get('种族') || get('体质') || get('灵根') || get('修炼路径') || get('宗门')) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[角色基础信息]</div>');
                outputParts.push('• 姓名：{{user}}<br>');
                if (get('性别')) outputParts.push('• 性别：' + get('性别').name + '「' + get('性别').desc + '」<br>');
                if (get('种族')) outputParts.push('• 种族：' + get('种族').name + '「' + get('种族').desc + '」<br>');
                if (get('体质') && get('体质').name !== '无') outputParts.push('• 特殊体质：' + get('体质').name + '「' + get('体质').desc + '」<br>');
                if (get('灵根')) outputParts.push('• 灵根：' + get('灵根').name + '「' + get('灵根').desc + '」<br>');
                if (get('修炼路径')) outputParts.push('• 修炼路径：' + get('修炼路径').name + '「' + get('修炼路径').desc + '」<br>');
                if (get('宗门')) outputParts.push('• 宗门：' + get('宗门').name + '「' + get('宗门').desc + '」<br>');
                outputParts.push('<br>');
            }

            if (get('容貌') || get('体型') || get('特殊特征')) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[外貌特征]</div>');
                if (get('容貌')) outputParts.push('• 容貌等级：' + get('容貌').name + '「' + get('容貌').desc + '」<br>');
                if (get('体型')) outputParts.push('• 身高体型：' + get('体型').name + '「' + get('体型').desc + '」<br>');
                if (get('特殊特征') && get('特殊特征').name !== '无') outputParts.push('• 特殊特征：' + get('特殊特征').name + '「' + get('特殊特征').desc + '」<br>');
                outputParts.push('<br>');
            }

            const attrNames = ['物攻', '法攻', '物防', '法防', '悟性', '气性', '气运', '魅力'];
            const hasNonDefaultAttr = attrNames.some(function(name) { return APP_STATE.attrs[name] && APP_STATE.attrs[name] !== 10; });
            if (hasNonDefaultAttr) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[基础属性]</div>');
                attrNames.forEach(function(attrName) {
                    const value = APP_STATE.attrs[attrName];
                    if (value !== undefined && value !== 10) {
                        const desc = getAttrDesc(attrName, value);
                        outputParts.push('• ' + attrName + '：' + value + '「' + desc + '」<br>');
                    }
                });
                outputParts.push('<br>');
            }

            if (get('身世')) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[基础信息]</div>');
                outputParts.push('• 身世：' + get('身世').name + '「' + get('身世').desc + '」<br><br>');
            }

            if (get('境界')) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[初始设定]</div>');
                outputParts.push('• 境界：' + get('境界').name + '「' + get('境界').desc + '」<br>');
                outputParts.push('<br>');
            }

            if (get('家族') || get('师门') || get('朋友')) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[初始关系]</div>');
                if (get('家族')) outputParts.push('• 家族关系：' + get('家族').name + '「' + get('家族').desc + '」<br>');
                if (get('师门')) outputParts.push('• 师门关系：' + get('师门').name + '「' + get('师门').desc + '」<br>');
                if (get('朋友')) outputParts.push('• 朋友关系：' + get('朋友').name + '「' + get('朋友').desc + '」<br>');
                outputParts.push('<br>');
            }

            const sideTasks = getArray('支线任务').filter(function(t) { return t.name !== '无支线任务'; });
            if ((get('主线任务') && get('主线任务').name !== '无主线任务') || sideTasks.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[初始任务]</div>');
                if (get('主线任务') && get('主线任务').name !== '无主线任务') {
                    outputParts.push('• 主线任务：' + get('主线任务').name + '「' + get('主线任务').desc + '」<br>');
                }
                sideTasks.forEach(function(t) { outputParts.push('• 支线任务：' + t.name + '「' + t.desc + '」<br>'); });
                outputParts.push('<br>');
            }

            if (get('灵石') && get('灵石').name !== '无') {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[开局资源]</div>');
                outputParts.push('• 灵石：' + get('灵石').name + '「' + get('灵石').desc + '」<br><br>');
            }

            const mechanismParts = [];
            if (get('业力') && get('业力').name !== '平衡业力') mechanismParts.push('• 业力：' + get('业力').name + '「' + get('业力').desc + '」<br>');
            if (get('因果') && get('因果').name !== '无') mechanismParts.push('• 因果：' + get('因果').name + '「' + get('因果').desc + '」<br>');
            if (get('转世') && get('转世').name !== '无') mechanismParts.push('• 转世：' + get('转世').name + '「' + get('转世').desc + '」<br>');
            if (get('天劫') && get('天劫').name !== '天劫正常') mechanismParts.push('• 天劫：' + get('天劫').name + '「' + get('天劫').desc + '」<br>');
            if (get('心魔') && get('心魔').name !== '心魔正常') mechanismParts.push('• 心魔：' + get('心魔').name + '「' + get('心魔').desc + '」<br>');
            if (get('寿命') && get('寿命').name !== '寿命正常') mechanismParts.push('• 寿命：' + get('寿命').name + '「' + get('寿命').desc + '」<br>');
            if (get('机缘') && get('机缘').name !== '机缘正常') mechanismParts.push('• 机缘：' + get('机缘').name + '「' + get('机缘').desc + '」<br>');

            if (mechanismParts.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[特殊机制]</div>');
                mechanismParts.forEach(function(p) { outputParts.push(p); });
                outputParts.push('<br>');
            }

            const talents = [].concat(getArray('战斗天赋'), getArray('辅助天赋'), getArray('特殊天赋'));
            if (talents.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[天赋能力]</div>');
                talents.forEach(function(t) { outputParts.push('• ' + t.name + '「' + t.desc + '」<br>'); });
                outputParts.push('<br>');
            }

            const lingenAttrs = getArray('灵根属性');
            if (lingenAttrs.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[灵根属性]</div>');
                lingenAttrs.forEach(function(a) { outputParts.push('• ' + a.name + '「' + a.desc + '」<br>'); });
                outputParts.push('<br>');
            }

            const resources = [].concat(getArray('功法'), getArray('法宝'), getArray('丹药'), getArray('材料'), getArray('特殊物品'));
            if (resources.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[初始资源]</div>');
                resources.forEach(function(r) { outputParts.push('• ' + r.name + '「' + r.desc + '」<br>'); });
                outputParts.push('<br>');
            }

            const equipParts = [];
            if (get('武器') && get('武器').name !== '无武器') equipParts.push('• 武器：' + get('武器').name + '「' + get('武器').desc + '」<br>');
            if (get('防具') && get('防具').name !== '无防具') equipParts.push('• 防具：' + get('防具').name + '「' + get('防具').desc + '」<br>');
            getArray('饰品').forEach(function(s) { equipParts.push('• 饰品：' + s.name + '「' + s.desc + '」<br>'); });

            if (equipParts.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[初始装备]</div>');
                equipParts.forEach(function(p) { outputParts.push(p); });
                outputParts.push('<br>');
            }

            const skillList = [].concat(getArray('战斗技能'), getArray('生活技能'));
            if (get('特殊技能') && get('特殊技能').name !== '无') {
                skillList.push(get('特殊技能'));
            }
            if (skillList.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[初始技能]</div>');
                skillList.forEach(function(s) { outputParts.push('• ' + s.name + '「' + s.desc + '」<br>'); });
                outputParts.push('<br>');
            }

            const petParts = [];
            if (get('战斗宠物') && get('战斗宠物').name !== '无战斗宠物') {
                petParts.push('• 战斗宠物：' + get('战斗宠物').name + '「' + get('战斗宠物').desc + '」<br>');
            }
            if (get('辅助宠物') && get('辅助宠物').name !== '无辅助宠物') {
                petParts.push('• 辅助宠物：' + get('辅助宠物').name + '「' + get('辅助宠物').desc + '」<br>');
            }
            if (petParts.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[灵兽宠物]</div>');
                petParts.forEach(function(p) { outputParts.push(p); });
                outputParts.push('<br>');
            }

            if (get('开局')) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[开局背景]</div>');
                outputParts.push('• 开局背景：' + get('开局').name + '「' + get('开局').desc + '」<br><br>');
            }

            const otherInfo = getArray('其他').filter(function(info) { return info.name !== '无其他信息'; });
            if (otherInfo.length > 0) {
                outputParts.push('<div style="margin:12px 0 6px;color:#4ECDC4;font-weight:700;">[其他补充信息]</div>');
                otherInfo.forEach(function(info) {
                    outputParts.push('• ' + info.name + '：' + info.desc + '<br>');
                });
                outputParts.push('<br>');
            }

            const previewEl = $('outputPreview');
            if (previewEl) {
                previewEl.innerHTML = outputParts.join('');
            }
        } catch (error) {
            console.error('更新预览时出错:', error);
        }
    }, 250);
}

// ==================== 页面渲染函数 ====================
function renderPage0() {
    // 点数选择页面
    return `
        <div class="section-title">
            <span>点数选择</span>
            <button class="random-btn" onclick="randomPoints()">🎲 随机</button>
        </div>
        <div class="option-group">
            ${[50, 100, 300, 500, 1000].map(p => `
                <div class="option-item ${APP_STATE.totalPoints === p ? 'selected' : ''}" 
                     onclick="setTotalPoints(${p})">
                    <span class="option-name">${p}点</span>
                </div>
            `).join('')}
        </div>

        <div class="custom-input">
            <div class="custom-input-row">
                <input type="number" id="customPointsInput" placeholder="输入自定义点数" min="0" style="flex:1">
                <button class="apply-btn" onclick="applyCustomPoints()">应用</button>
            </div>
        </div>

        <div class="section-title">
            <span>基础属性</span>
            <button class="random-btn" onclick="randomAttrs()">🎲 随机</button>
        </div>
        ${Object.keys(APP_STATE.attrs).map(attrName => `
            <div class="attr-selector">
                <div class="attr-header">
                    <span class="attr-name">${attrName}</span>
                    <span class="attr-value">${APP_STATE.attrs[attrName]}</span>
                </div>
                <div class="attr-controls">
                    <button class="attr-btn" onclick="adjustAttr('${attrName}', -10)">--</button>
                    <button class="attr-btn" onclick="adjustAttr('${attrName}', -1)">-</button>
                    <input class="attr-input" type="number" value="${APP_STATE.attrs[attrName]}" 
                           onchange="setAttr('${attrName}', this.value)" min="-100" max="1000">
                    <button class="attr-btn" onclick="adjustAttr('${attrName}', 1)">+</button>
                    <button class="attr-btn" onclick="adjustAttr('${attrName}', 10)">++</button>
                </div>
                <input type="range" class="attr-slider" value="${APP_STATE.attrs[attrName]}" 
                       min="-100" max="1000" step="1" 
                       oninput="updateAttrDisplay('${attrName}', this.value)"
                       onchange="setAttr('${attrName}', this.value)">
                <div class="attr-desc">${getAttrDesc(attrName, APP_STATE.attrs[attrName])}</div>
            </div>
        `).join('')}
    `;
}

