}

function randomAttrs() {
    for (let key in APP_STATE.attrs) {
        if (key === '气运') {
            // 气运属性范围是0-1000
            APP_STATE.attrs[key] = Math.floor(Math.random() * 1001);
        } else {
            // 其他属性范围是0-100
            APP_STATE.attrs[key] = Math.floor(Math.random() * 101);
        }
    }
    renderCurrentPage();
    updateRemainingPoints();
}

function randomModule(moduleIndex, shouldRender = true) {
    // 随机模块内所有选项
    const module = MODULES_DATA[moduleIndex];
    module.sections.forEach(section => {
        const options = section.options;
        const randomOpt = options[Math.floor(Math.random() * options.length)];

        if (section.isMultiSelect) {
            // 多选模块：随机选择1到maxSelect个选项
            const maxSelect = section.maxSelect || 1;
            const numToSelect = Math.floor(Math.random() * maxSelect) + 1; // 随机选择1到maxSelect个
            const shuffled = [...options].sort(() => 0.5 - Math.random()); // 打乱选项顺序
            const selected = shuffled.slice(0, numToSelect);
            APP_STATE.selections[section.key] = selected;
        } else {
            // 单选模块：随机选择1个选项
            APP_STATE.selections[section.key] = randomOpt;
        }
    });
    // 根据参数决定是否渲染页面，避免批量随机时重复渲染
    if (shouldRender) {
        renderCurrentPage();
        updateRemainingPoints();
    }
}

