function selectOptionByIndex(moduleIdx, sectionIdx, optIdx) {
    if (APP_STATE.isRendering) {
        return;
    }

    const module = MODULES_DATA[moduleIdx];
    if (!module) return;

    const section = module.sections[sectionIdx];
    if (!section) return;

    const option = section.options[optIdx];
    if (!option) return;

    if (section.isMultiSelect) {
        if (!APP_STATE.selections[section.key]) {
            APP_STATE.selections[section.key] = [];
        }

        const selections = APP_STATE.selections[section.key];
        const existingIdx = selections.findIndex(s => s.name === option.name);

        if (existingIdx >= 0) {
            selections.splice(existingIdx, 1);
            if (selections.length === 0) {
                delete APP_STATE.selections[section.key];
            }
        } else {
            const maxSelect = section.maxSelect || 999;
            if (selections.length < maxSelect) {
                selections.push(option);
            } else {
                alert('最多只能选择' + maxSelect + '个选项！');
                return;
            }
        }
    } else {
        const currentSelection = APP_STATE.selections[section.key];

        if (currentSelection && currentSelection.name === option.name) {
            delete APP_STATE.selections[section.key];
        } else {
            APP_STATE.selections[section.key] = option;
        }
    }

    renderCurrentPage();
    updateRemainingPoints();
}

function selectOption(key, optStr) {
    // 选择选项（保留兼容）
    const opt = typeof optStr === 'string' ? JSON.parse(optStr) : optStr;
    APP_STATE.selections[key] = opt;
    renderCurrentPage();
    updateRemainingPoints();
}

function clearAll() {
    APP_STATE.totalPoints = 100;
    for (let key in APP_STATE.attrs) {
        APP_STATE.attrs[key] = 10;
