function importFromText() {
    var textarea = document.getElementById('importTextArea');
    if (!textarea) {
        alert('找不到导入文本框');
        return;
    }

    var text = textarea.value.trim();
    if (!text) {
        alert('请输入要导入的JSON内容，或拖入JSON文件');
        return;
    }

    // 尝试解析JSON
    var jsonData = null;
    try {
        jsonData = JSON.parse(text);
    } catch (e) {
        alert('JSON格式错误：' + e.message + '\n\n请确保粘贴的是有效的JSON内容（以 { 开头，以 } 结尾）');
        return;
    }

