function initPresetArchive() {
    const archives = JSON.parse(localStorage.getItem('wanyu-archives') || '[]');

    // 检查是否已有预设存档（通过isPreset标记识别）
    const existingPreset = archives.find(arch => arch.isPreset === true);

    // 只在没有预设存档时才创建
    if (!existingPreset) {
        console.log('首次创建预设存档...');
        const presetArchive = getPresetArchiveData();
        archives.unshift(presetArchive); // 插入到第一位
        localStorage.setItem('wanyu-archives', JSON.stringify(archives));
        console.log('✅ 预设存档创建成功');
    } else {
        console.log('预设存档已存在，保留用户编辑的内容');
    }
}

function restorePresetArchive() {
    // 复原预设存档到初始状态
    if (!confirm('确定要将预设存档复原到初始状态吗？这将覆盖您对预设存档的所有修改！')) {
        return;
    }

    const archives = JSON.parse(localStorage.getItem('wanyu-archives') || '[]');
    const presetIndex = archives.findIndex(arch => arch.isPreset === true);

    if (presetIndex >= 0) {
        // 获取原始预设数据并覆盖
        const originalPreset = getPresetArchiveData();
        archives[presetIndex] = originalPreset;
        localStorage.setItem('wanyu-archives', JSON.stringify(archives));

        alert('✅ 预设存档已复原到初始状态！');
        renderCurrentPage(); // 刷新页面显示
    } else {
        alert('❌ 未找到预设存档！');
    }
}

