                await this._syncFromBook();
                this.paint();
                this.ready = true;
            },

            _applyDefaults: function () {
                var self = this;
                self.diffIdx = 6;
                NPC_TABLE.forEach(function (c) {
                    self.npcMap[c.m] = c.md;
                    self.npcMap[c.f] = c.fd;
                });
                DLC_TABLE.forEach(function (g) {
                    g.items.forEach(function (it) {
                        self.dlcMap[it.entry] = it.on;
                    });
                });
            },

            _syncFromBook: async function () {
                var self = this;
                var bn = await WB.getName();
                if (!bn) return;
                var entries = await WB.readAll(bn);
                if (!entries.length) return;
                var stateMap = {};
                entries.forEach(function (e) { stateMap[e.name] = e.enabled; });
                DIFF_TABLE.forEach(function (d, i) {
                    if (stateMap[d.entry] === true) self.diffIdx = i;
                });
                Object.keys(self.npcMap).forEach(function (k) {
                    if (k in stateMap) self.npcMap[k] = !!stateMap[k];
                });
                Object.keys(self.dlcMap).forEach(function (k) {
                    if (k in stateMap) self.dlcMap[k] = !!stateMap[k];
                });
            },

            paint: function () {
                this._renderDiff();
                this._renderNpc();
                this._renderDlcSubWw156651();
                this._renderDlcSubYu();
                this._renderDlcSubAcacai();
                this._renderDlcSubAkimekaze();
                this._renderDlcSubMyrtenaster();
                this._renderStatus();
            },

            _renderDiff: function () {
                var self = this;
                var box = document.getElementById('sheet-difficulty');
                if (!box) return;
                var html = '<div class="diff-list">';
                DIFF_TABLE.forEach(function (d, i) {
                    var stars = '';
                    for (var s = 0; s < 10; s++) stars += s < i + 1 ? '★' : '☆';
                    var cls = i === self.diffIdx ? 'diff-item picked' : 'diff-item';
                    html += '<div class="' + cls + '" onclick="DLCCtrl.pickDiff(' + i + ')">'
                        + '<span class="d-stars">' + stars + '</span>'
                        + '<div class="d-body">'
                        + '<div class="d-name">' + d.title + '</div>'
                        + '<div class="d-note">' + d.tip + '</div>'
                        + '</div></div>';
                });
                html += '</div>';
                box.innerHTML = html;
            },

            _renderNpc: function () {
