            _renderStatus: function () {
                var di = DIFF_TABLE[this.diffIdx];
                document.getElementById('svDiff').textContent = di.tag + '·' + di.title;

                var npcOn = 0, npcAll = 0;
                for (var k in this.npcMap) {
                    npcAll++;
                    if (this.npcMap[k]) npcOn++;
                }
                document.getElementById('svNpc').textContent = npcOn + '/' + npcAll;

                var dlcOn = 0, dlcAll = 0;
                for (var d in this.dlcMap) {
                    dlcAll++;
                    if (this.dlcMap[d]) dlcOn++;
                }
                document.getElementById('svDlc').textContent = dlcOn + '/' + dlcAll;
            },

            pickDiff: function (idx) {
                this.diffIdx = idx;
                this._renderDiff();
                this._renderStatus();
            },

            flipNpc: function (key, val) {
                this.npcMap[key] = val;
                var npc = NPC_TABLE.find(c => c.m === key || c.f === key);
                if (npc) {
                    if (npc.m === key) npc.md = val;
                    if (npc.f === key) npc.fd = val;
                }
                this._renderStatus();
                this._commitToBook();
            },

            setNpcAll: function (enable) {
                var self = this;
                var npcStart = NPC_TABLE.findIndex(c => c.name === '林墨');
                var npcEnd = NPC_TABLE.findIndex(c => c.name === '云逍遥');
                NPC_TABLE.forEach(function (c, idx) {
                    if (idx >= npcStart && idx <= npcEnd) {
                        if (c.m && c.f) {
                            self.npcMap[c.m] = enable;
                            self.npcMap[c.f] = false;
                            c.md = enable;
                            c.fd = false;
                        } else if (c.m) {
                            self.npcMap[c.m] = enable;
                            c.md = enable;
                        } else if (c.f) {
                            self.npcMap[c.f] = enable;
                            c.fd = enable;
                        }
                    } else {
                        if (c.m) {
                            self.npcMap[c.m] = enable;
                            c.md = enable;
                        }
                        if (c.f) {
                            self.npcMap[c.f] = enable;
                            c.fd = enable;
                        }
                    }
                });
                this._renderStatus();
                this._renderNpc();
                this._commitToBook();
            },

