                } else if (subSheetId === '钰') {
                    DLC_TABLE.forEach(function (g) {
                        if (g.group === '反派系统') {
                            g.items.forEach(function (it) {
                                it.on = enable;
                                entries.push(it.entry);
                            });
                        }
                    });
                } else if (subSheetId === '阿菜菜') {
                    DLC_TABLE.forEach(function (g) {
                        if (g.group === '生物种类' || g.group === '世家人物' || g.group === '世家' || g.group === '凡人武道') {
                            g.items.forEach(function (it) {
                                it.on = enable;
                                entries.push(it.entry);
                            });
                        }
                    });
                } else if (subSheetId === 'akimekaze') {
                    DLC_TABLE.forEach(function (g) {
                        if (g.group === '势力专属事务与事件' || g.group === '血衣楼') {
                            g.items.forEach(function (it) {
                                it.on = enable;
                                entries.push(it.entry);
                            });
                        }
                    });
                } else if (subSheetId === 'myrtenaster') {
                    DLC_TABLE.forEach(function (g) {
                        if (g.group === '琼华京') {
                            g.items.forEach(function (it) {
                                it.on = enable;
                                entries.push(it.entry);
                            });
                        }
                    });
                }
                entries.forEach(function (entry) {
                    self.dlcMap[entry] = enable;
                });
                this._renderStatus();
                this._renderDlcSubWw156651();
                this._renderDlcSubYu();
                this._renderDlcSubAcacai();
                this._renderDlcSubAkimekaze();
                this._renderDlcSubMyrtenaster();
                this._commitToBook();
            },

            flipDlc: function (key, val) {
                this.dlcMap[key] = val;
                var dlc = DLC_TABLE.flatMap(g => g.items).find(it => it.entry === key);
                if (dlc) dlc.on = val;
                this._renderStatus();
                this._commitToBook();
            },

            switchSheet: function (sheetId) {
                document.querySelectorAll('.dlc-tab-item').forEach(function (t) {
                    t.classList.toggle('on', t.getAttribute('data-sheet') === sheetId);
                });
                document.querySelectorAll('.dlc-sheet').forEach(function (s) {
                    s.classList.toggle('on', s.id === 'sheet-' + sheetId);
                });
            },

            switchSubSheet: function (subSheetId) {
                document.querySelectorAll('.dlc-subnav-item').forEach(function (t) {
                    t.classList.toggle('on', t.getAttribute('data-subsheet') === subSheetId);
                });
                document.querySelectorAll('.dlc-subsheet').forEach(function (s) {
                    s.classList.toggle('on', s.id === 'subsheet-' + subSheetId);
                });
            },

            _commitToBook: async function () {
                var self = this;
                var bn = await WB.getName();
                if (!bn) return;
                var pairs = [];
                DIFF_TABLE.forEach(function (d, i) {
                    pairs.push({ name: d.entry, enabled: i === self.diffIdx });
                });
                Object.keys(self.npcMap).forEach(function (k) {
                    pairs.push({ name: k, enabled: self.npcMap[k] });
                });
                Object.keys(self.dlcMap).forEach(function (k) {
                    pairs.push({ name: k, enabled: self.dlcMap[k] });
                });
                await WB.writeBatch(bn, pairs);
            },

            exportLocal: function () {
                var snapshot = {
                    diff: this.diffIdx,
                    npc: Object.assign({}, this.npcMap),
                    dlc: Object.assign({}, this.dlcMap)
                };
                localStorage.setItem('dlcSnapshot', JSON.stringify(snapshot));
                alert('设置已保存到本地');
            },

            importLocal: function () {
                try {
                    var raw = localStorage.getItem('dlcSnapshot');
                    if (!raw) { alert('未找到本地存档'); return; }
                    var data = JSON.parse(raw);
                    if (typeof data.diff === 'number' && data.diff >= 0 && data.diff < DIFF_TABLE.length) {
                        this.diffIdx = data.diff;
                    }
                    if (data.npc) {
                        for (var k in data.npc) {
                            if (k in this.npcMap) this.npcMap[k] = !!data.npc[k];
                        }
                    }
                    if (data.dlc) {
                        for (var d in data.dlc) {
                            if (d in this.dlcMap) this.dlcMap[d] = !!data.dlc[d];
                        }
                    }
                    this.paint();
                    alert('设置已加载');
                } catch (e) {
                    alert('加载失败：数据格式异常');
                }
            },

            resetAll: function () {
                this._applyDefaults();
                this.paint();
            },

            goNext: async function () {
                await this._commitToBook();
                APP_STATE.dlcSelections = Object.assign({}, this.dlcMap);
                showPage(2);
            }
        };
    </script>
</body>
