import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

/**
 * 辅助函数：数值限制
 */
const clampNum = (min, max, prefault) => {
  return z.coerce.number().prefault(prefault).transform(v => _.clamp(v, min, max));
};

/* ========== 行程信息自动计算工具 ========== */
const TRAVEL_VARIANCE = 0.2;  // 速度波动 ±20%

/**
 * 核心逻辑：境界解析与速度映射
 * 采用从高到低匹配，防止"大罗金仙"被错误匹配为"金仙"
 */
function _getRealmSpeedInfo(realmStr) {
  // 按照你的体系从高到底排列 (凡人=5, 筑基=8 (+3), 以此类推每大境界+3)
  const realms = [
    { keys: ["圣人", "混元"], speed: 47, name: "圣人" },
    { keys: ["准圣"], speed: 44, name: "准圣" },
    { keys: ["大罗"], speed: 41, name: "大罗金仙" },
    { keys: ["太乙"], speed: 38, name: "太乙金仙" },
    { keys: ["金仙"], speed: 35, name: "金仙" },
    { keys: ["天仙"], speed: 32, name: "天仙" },
    { keys: ["地仙"], speed: 29, name: "地仙" },
    { keys: ["大乘"], speed: 26, name: "大乘期" },
    { keys: ["渡劫"], speed: 23, name: "渡劫期" },
    { keys: ["合体"], speed: 20, name: "合体期" },
    { keys: ["化神"], speed: 17, name: "化神期" },
    { keys: ["元婴"], speed: 14, name: "元婴期" },
    { keys: ["金丹", "结丹"], speed: 11, name: "金丹期" },
    { keys: ["筑基"], speed: 8, name: "筑基期" },
    { keys: ["练气", "炼气"], speed: 5, name: "练气期" },
    { keys: ["凡人", "凡", "普通"], speed: 5, name: "凡人" }
  ];

  const defaultInfo = { speed: 5, name: "凡人" };
  if (!realmStr || typeof realmStr !== 'string') return defaultInfo;

  // 遍历匹配：只要包含关键字（如"筑基后期"包含"筑基"），就判定为该境界
  for (let i = 0; i < realms.length; i++) {
    for (let key of realms[i].keys) {
      if (realmStr.includes(key)) {
        return realms[i];
      }
    }
  }
  return defaultInfo; // 找不到匹配项，默认凡人
}

function _travelDist(x1, y1, x2, y2) {
  return Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2) * 2;
}

function _travelFmtDur(hours) {
  if (hours < 1) return '不到1小时';
  let h = Math.round(hours);
  if (h < 24) return h + '小时';
  let d = Math.floor(h / 24), rh = h % 24;
  if (d < 30) return rh ? d + '天' + rh + '小时' : d + '天';
  let m = Math.floor(d / 30), rd = d % 30;
  if (m < 12) return rd ? m + '个月' + rd + '天' : m + '个月';
  let y = Math.floor(m / 12), rm = m % 12;
  return rm ? y + '年' + rm + '个月' : y + '年';
}

function _travelFmtRange(minH, maxH) {
  const a = _travelFmtDur(minH), b = _travelFmtDur(maxH);
  if (a === b) return '约' + a;
  const re = /^(\d+)(小时|天|个月|年)$/;
  const ma = a.match(re), mb = b.match(re);
  if (ma && mb && ma[2] === mb[2]) return ma[1] + '~' + mb[1] + mb[2];
  return a + '~' + b;
}

// 增加 currentRealm 参数
function _travelGenInfo(cx, cy, tx, ty, currentRealm) {
  const dist = _travelDist(cx, cy, tx, ty);
  if (dist < 0.1) return '已在此处'; 

  const dStr = dist < 1 ? Math.round(dist * 1000) + '米'
    : dist < 100 ? (Math.round(dist * 10) / 10) + '公里'
    : Math.round(dist) + '公里';

  // 解析境界与速度
  const realmInfo = _getRealmSpeedInfo(currentRealm);
  const minH = dist / (realmInfo.speed * (1 + TRAVEL_VARIANCE));
  const maxH = dist / (realmInfo.speed * (1 - TRAVEL_VARIANCE));

  return `距离所处地点 ${dStr}，${realmInfo.name}无加速因素时预期到达所需时间 ${_travelFmtRange(minH, maxH)}`;
}

/* ========== AvatarSchema辅助函数 ========== */
const normalizeHue = (value) => {
  const n = Number(value);
  if (!Number.isFinite(n)) return 0;
  const wrapped = ((n % 360) + 360) % 360;
