/**
 * 数值型子属性辅助函数：{当前, 上限} 结构
 * 当前值不低于0；上限支持特殊哨兵值 -1 表示"无穷/无上限"(任何负数都会被归一化为-1)，
 * 其余情况保持原样，不做任何强制清零处理，避免AI设定的无穷上限被意外破坏
 */
const getGaugeSchema = (curDefault, maxDefault) => {
  return z.object({
    当前: z.coerce.number().prefault(curDefault).transform(v => Math.max(0, v)),
