/**
 * 遍历已知地点，计算并写入行程信息（直接修改 stat_data 对象）
 */
function computeTravelInfoForMap(statData) {
  try {
    const mapData = statData && statData.地图;
    if (!mapData) return;

    // 1. 安全读取主角境界（使用数组路径避免点号分割问题）
    const currentRealm = _.get(statData, ['主角信息', '境界'], '凡人');

    // 2. 【修复】直接用方括号访问 schema 定义的扁平键名

    const cx = Number(mapData['当前坐标X']) || 0;
    const cy = Number(mapData['当前坐标Y']) || 0;

    // 3. 处理已知地点
    if (mapData.已知地点) {
      const places = mapData.已知地点;
      for (const name of Object.keys(places)) {
        const place = places[name];
        if (!place) continue;

        // 【智能覆盖保护机制】：
        const oldInfo = place.行程信息 || "";
        if (oldInfo && !oldInfo.startsWith('距离所处地点') && !oldInfo.includes('已在此处')) {
            continue;
        }

        const tx = Number(place['坐标X']) || 0;
        const ty = Number(place['坐标Y']) || 0;

        // 传入主角境界计算新时间并覆盖
        place.行程信息 = _travelGenInfo(cx, cy, tx, ty, currentRealm);
      }
    }

  } catch (e) {
    console.error('[行程计算] 执行失败:', e);
  }
}

/**
 * 标准的Schema注册函数
 */
function registerSchemaWhenReady() {
  if (typeof registerMvuSchema === 'function') {
    try {
      registerMvuSchema(Schema);
      console.log('MVU Schema注册成功');

      // 注册行程信息自动计算钩子
      if (typeof eventOn === 'function') {
        // 钩子1：变量初始化时（打开聊天/切换角色卡）
        eventOn('mag_variable_initialized', (t) => {
          if (t && t.stat_data) computeTravelInfoForMap(t.stat_data);
        });

        // 钩子2：AI 输出导致变量更新完毕后
        eventOn('mag_variable_update_ended_for_zod', (t) => {
          if (t && t.stat_data) computeTravelInfoForMap(t.stat_data);
        });

        // 钩子3：命令解析全部完成后（覆盖 insert/replace 新增地点的场景）
        eventOn('mag_command_parsed_ended_for_zod', (t) => {
          if (t && t.stat_data) computeTravelInfoForMap(t.stat_data);
        });

        console.log('[行程计算] 事件钩子注册成功');
      } else {
        console.warn('[行程计算] eventOn 不可用，行程信息将仅在前端展示');
      }

    } catch (error) {
      console.error('MVU Schema注册失败:', error);
    }
  } else {
    setTimeout(registerSchemaWhenReady, 100);
  }
}

// 在文档加载完成后调用注册函数
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', registerSchemaWhenReady);
} else {
  registerSchemaWhenReady();
}

